// ─── EXAM DATA ────────────────────────────────────────────────────────────────

const QUESTIONS_E01 = [
  { id:1, domain:'D1: Architecture', multi:false, text:"Which Snowflake layer is responsible for authentication, query optimization, and metadata management?", options:{A:"Storage Layer",B:"Cloud Services Layer",C:"Compute Layer",D:"Data Exchange Layer"}, answer:["B"], explanation:"Cloud Services handles auth, query parsing/optimization, metadata, access control, and the result cache. Storage stores data. Compute executes queries." },
  { id:2, domain:'D1: Architecture', multi:false, text:"What is the purpose of a file format object in Snowflake?", options:{A:"To define the physical layout of micro-partitions.",B:"To define a reusable set of data parsing options for loading and unloading.",C:"To specify the encryption method for staged files.",D:"To create a mapping between external and internal column names."}, answer:["B"], explanation:"A file format is a named, reusable object that defines parsing options (TYPE, DELIMITER, SKIP_HEADER, etc.) used with COPY INTO and stages." },
  { id:3, domain:'D1: Architecture', multi:false, text:"A Large warehouse runs for exactly 1 hour. How many credits are consumed?", options:{A:"4 credits",B:"8 credits",C:"16 credits",D:"1 credit"}, answer:["B"], explanation:"Credits per hour by size: XS=1, S=2, M=4, L=8, XL=16. Large = 8 credits/hour." },
  { id:4, domain:'D1: Architecture', multi:false, text:"Why is the PRIMARY KEY constraint used on standard tables in Snowflake?", options:{A:"To enforce uniqueness and prevent duplicate rows.",B:"To cluster data and improve query performance.",C:"To indicate unique identifiers for metadata and documentation purposes.",D:"To encrypt the primary key column automatically."}, answer:["C"], explanation:"Snowflake PRIMARY KEY constraints are informational/metadata ONLY. They are NOT enforced. Duplicates ARE allowed. They indicate intended identifiers for documentation and BI tools." },
  { id:5, domain:'D1: Architecture', multi:false, text:"A materialized view references a base table. The base table has a column dropped. What happens to the materialized view?", options:{A:"The MV automatically adapts to the new schema.",B:"The MV may become invalid if it referenced the dropped column.",C:"The MV is automatically dropped.",D:"Nothing, MVs are independent of the base table schema."}, answer:["B"], explanation:"If a column referenced by the MV is dropped from the base table, the MV becomes invalid. From real exam: this is a key consideration when using MVs." },
  { id:6, domain:'D1: Architecture', multi:true, text:"What is the impact of selecting one Snowflake edition over another? (Select TWO).", options:{A:"The edition will impact the unit costs for storage.",B:"The edition will impact which regions can be accessed.",C:"The edition will determine the unit costs for compute credits.",D:"The edition will impact the total allowed storage space.",E:"The edition will set a limit on compute credits that can be consumed."}, answer:["A","C"], explanation:"Higher editions have higher unit costs for both storage and compute. Editions do NOT limit regions, storage space, or credit consumption." },
  { id:7, domain:'D1: Architecture', multi:false, text:"What does the parameter hierarchy mean in Snowflake?", options:{A:"Account settings always override session settings.",B:"Object-level settings override session settings, which override account settings.",C:"Session settings are the only level that can be changed.",D:"All parameters must be set at the account level."}, answer:["B"], explanation:"Parameter precedence: Object > Session > Account. The most specific level wins." },
  { id:8, domain:'D1: Architecture', multi:false, text:"Snowpark DataFrames are evaluated lazily. Where does the computation actually execute?", options:{A:"On the client machine running the Python code.",B:"On the Snowflake virtual warehouse assigned to the session.",C:"In a Snowflake-managed serverless pool.",D:"On a dedicated Snowpark compute cluster."}, answer:["B"], explanation:"Snowpark pushes computation to the session's warehouse. The client builds the plan lazily; evaluation runs SQL on the warehouse." },
  { id:9, domain:'D1: Architecture', multi:false, text:"What type of warehouse provides 16x more memory per node for ML training workloads?", options:{A:"Standard Gen 1",B:"Standard Gen 2",C:"Snowpark-optimized",D:"Multi-cluster warehouse"}, answer:["C"], explanation:"Snowpark-optimized warehouses have 16x memory-to-compute ratio. Designed for ML training, large UDFs, and memory-intensive Snowpark operations." },
  { id:10, domain:'D1: Architecture', multi:true, text:"Which TWO activities can be monitored directly from the Snowsight Activity tab? (Select TWO).", options:{A:"Login history",B:"Query history",C:"Copy history",D:"Event usage history",E:"Warehouse metering history"}, answer:["B","C"], explanation:"The Snowsight Activity tab shows Query History and Copy History directly. Login, events, and warehouse metering require ACCOUNT_USAGE views." },
  { id:11, domain:'D2: Security', multi:false, text:"Which system role is specifically designed to create and manage users and roles?", options:{A:"SYSADMIN",B:"SECURITYADMIN",C:"USERADMIN",D:"ACCOUNTADMIN"}, answer:["C"], explanation:"USERADMIN creates/manages users and roles. SYSADMIN creates DBs/warehouses. SECURITYADMIN manages object grants. ACCOUNTADMIN manages billing/account settings." },
  { id:12, domain:'D2: Security', multi:false, text:"What type of encryption does Snowflake use by default for data at rest on ALL editions?", options:{A:"AES-128",B:"AES-256",C:"RSA-2048",D:"TLS 1.2"}, answer:["B"], explanation:"All editions: AES-256 at rest, TLS 1.2 in transit. Tri-Secret Secure (customer-managed keys) requires Business Critical+." },
  { id:13, domain:'D2: Security', multi:false, text:"In a managed access schema, who can grant privileges on objects? (Select the BEST answer).", options:{A:"Any role that owns an object in the schema.",B:"Only the schema owner and roles with MANAGE GRANTS privilege.",C:"Only ACCOUNTADMIN.",D:"Any role with USAGE on the schema."}, answer:["B"], explanation:"In a managed access schema, ONLY the schema owner and MANAGE GRANTS roles can grant privileges. Individual object owners CANNOT grant access (unlike regular schemas)." },
  { id:14, domain:'D2: Security', multi:false, text:"A company needs to protect PHI data and requires HIPAA compliance. What is the minimum Snowflake edition?", options:{A:"Standard",B:"Enterprise",C:"Business Critical",D:"Virtual Private Snowflake"}, answer:["C"], explanation:"Business Critical is the minimum for HIPAA/PHI compliance, Tri-Secret Secure, and PrivateLink." },
  { id:15, domain:'D2: Security', multi:false, text:"What is it called when a customer-managed key is combined with a Snowflake-managed key to create a composite encryption key?", options:{A:"Hierarchical key model",B:"Client-side encryption",C:"Tri-Secret Secure",D:"Key-pair authentication"}, answer:["C"], explanation:"Tri-Secret Secure combines customer KMS key + Snowflake key = composite encryption key. Requires Business Critical+." },
  { id:16, domain:'D2: Security', multi:true, text:"Which TWO criteria does Snowflake use to determine the current role when a session starts? (Select TWO).", options:{A:"If a role was specified in the connection and granted to the user, that role becomes current.",B:"If no role was specified and a default role is set, the default role becomes current.",C:"If no role was specified and no default is set, the login fails.",D:"If a specified role is not granted to the user, it is silently ignored.",E:"If a specified role is not granted, it is automatically granted."}, answer:["A","B"], explanation:"A: Specified + granted = becomes current. B: No role specified = default role used. C is wrong (PUBLIC is used, login succeeds). D is wrong (error, not silent). E is wrong (not auto-granted)." },
  { id:17, domain:'D2: Security', multi:false, text:"A column has a masking policy applied. An analyst needs to see the full values but currently sees masked data. What should be changed?", options:{A:"Grant the analyst ACCOUNTADMIN role.",B:"Modify the masking policy to include the analyst's role.",C:"Remove the masking policy from the column.",D:"Grant the analyst OWNERSHIP on the table."}, answer:["B"], explanation:"Modify the policy to include the analyst's role. ACCOUNTADMIN does NOT bypass masking. Removing the policy or granting OWNERSHIP are overkill." },
  { id:18, domain:'D3: Loading', multi:false, text:"What is the default file format for unloading data using COPY INTO <location>?", options:{A:"JSON",B:"CSV",C:"Parquet",D:"Avro"}, answer:["B"], explanation:"Default unload format is CSV with gzip compression." },
  { id:19, domain:'D3: Loading', multi:false, text:"Which information is put in the STORAGE_ALLOWED_LOCATIONS parameter when creating a storage integration?", options:{A:"A table name.",B:"A user, table, or named internal stage.",C:"A cloud provider name.",D:"S3 bucket, GCS bucket, or Azure container folder path."}, answer:["D"], explanation:"STORAGE_ALLOWED_LOCATIONS specifies the cloud storage paths that the integration is allowed to access." },
  { id:20, domain:'D3: Loading', multi:true, text:"What mechanisms can trigger Snowpipe to load staged files? (Select TWO).", options:{A:"Cloud messaging (S3 SQS, Azure Event Grid, GCS Pub/Sub)",B:"Email integrations",C:"Error notifications",D:"REST API endpoints (insertFiles)",E:"Snowsight button clicks"}, answer:["A","D"], explanation:"Snowpipe is triggered by: 1) Cloud event notifications (AUTO_INGEST=TRUE) or 2) REST API calls (insertFiles endpoint)." },
  { id:21, domain:'D3: Loading', multi:false, text:"A user needs to upload a file from their local machine to their personal default stage in a folder called current_data. Which command?", options:{A:"PUT file:///sales.csv @current_data",B:"PUT file:///sales.csv @~/current_data",C:"PUT file:///sales.csv @%current_data",D:"COPY INTO @~/current_data FROM file:///sales.csv"}, answer:["B"], explanation:"@~ is the user stage (personal default). @% is the table stage. PUT to @~/current_data uploads into that subfolder. COPY INTO does not upload local files." },
  { id:22, domain:'D3: Loading', multi:false, text:"What does the VALIDATION_MODE parameter do in COPY INTO?", options:{A:"Validates data and loads it, logging errors to a table.",B:"Validates data without loading it and returns any errors found.",C:"Validates the target table schema before loading.",D:"Validates credentials for the stage connection."}, answer:["B"], explanation:"VALIDATION_MODE is a dry-run. NO data is loaded. It validates and returns errors. Useful for pre-checking files." },
  { id:23, domain:'D3: Loading', multi:false, text:"What does adding PARTITION BY in a COPY INTO <location> (unload) command do?", options:{A:"Partitions the target table for faster queries.",B:"Splits unloaded table rows into separate files based on column values.",C:"Defines a partitioning scheme for the stage.",D:"Filters rows to unload based on partition values."}, answer:["B"], explanation:"PARTITION BY in COPY INTO unload splits output into separate files by column values. Example: PARTITION BY (region) creates one file per region." },
  { id:24, domain:'D3: Loading', multi:false, text:"How does a stream in Snowflake know when it will become stale?", options:{A:"By using DATA_RETENTION_TIME_IN_DAYS alone.",B:"By using the lesser of retention and MAX_DATA_EXTENSION_TIME_IN_DAYS.",C:"By using the greater of retention and MAX_DATA_EXTENSION_TIME_IN_DAYS.",D:"By using the sum of both values."}, answer:["C"], explanation:"Stream staleness = the GREATER of DATA_RETENTION_TIME_IN_DAYS and MAX_DATA_EXTENSION_TIME_IN_DAYS. The extension keeps the stream alive longer." },
  { id:25, domain:'D3: Loading', multi:false, text:"When creating an external stage for S3, what is the primary security benefit of using a STORAGE INTEGRATION?", options:{A:"It encrypts files in the bucket using Snowflake keys.",B:"It grants temporary permissions to unload data.",C:"It deploys stored procedures from a private Git repository.",D:"It avoids storing hard-coded credentials in the stage definition."}, answer:["D"], explanation:"Storage integrations use IAM trust relationships. The primary benefit is avoiding hard-coded AWS keys in stage definitions." },
  { id:26, domain:'D3: Loading', multi:false, text:"A company needs continuous, automatic data loading from S3 into Snowflake as soon as files appear. Which tool meets this requirement?", options:{A:"Snowflake CLI",B:"Snowpipe",C:"Snowpark",D:"SnowSQL"}, answer:["B"], explanation:"Snowpipe provides continuous, automatic ingestion triggered by cloud event notifications. CLI, SnowSQL, and Snowpark are for running commands/code, not continuous auto-ingestion." },
  { id:27, domain:'D4: Performance', multi:false, text:"A warehouse shows consistent spilling (local and remote) AND queuing during peak hours. What is the MOST efficient solution?", options:{A:"Increase the warehouse size.",B:"Use a multi-cluster warehouse with STANDARD scaling.",C:"Use a multi-cluster warehouse with ECONOMY scaling.",D:"Shorten the STATEMENT_QUEUED_TIMEOUT_IN_SECONDS."}, answer:["B"], explanation:"Spilling needs more resources AND queuing needs more concurrency. Multi-cluster with STANDARD scaling addresses BOTH: larger effective compute + immediate cluster addition for concurrency. Scale up alone only fixes spilling." },
  { id:28, domain:'D4: Performance', multi:false, text:"A Query Profile shows all partitions are being scanned on a table with no clustering key. Queries filter on a date column with 3,000 distinct values. Best optimization?", options:{A:"Enable Search Optimization Service on the date column.",B:"Add a clustering key on the date column.",C:"Enable Query Acceleration Service.",D:"Create a materialized view."}, answer:["B"], explanation:"Low-medium cardinality (3,000 values) + filter column + poor pruning = clustering key. SOS is for high-cardinality equality lookups. QAS is for outlier queries." },
  { id:29, domain:'D4: Performance', multi:false, text:"Which type of query would benefit MOST from enabling the Query Acceleration Service?", options:{A:"Queries with no filters or aggregation.",B:"Queries that are queued in the warehouse.",C:"Queries that use more resources than the typical query.",D:"All queries benefit equally from QAS."}, answer:["C"], explanation:"QAS accelerates outlier queries that use significantly more resources than typical. It does not help queuing (use multi-cluster) or filterless queries." },
  { id:30, domain:'D4: Performance', multi:true, text:"Based on Query Profile analysis, which TWO columns benefit MOST from a clustering key? (Select TWO).", options:{A:"A column frequently in ORDER BY operations.",B:"A column frequently in WHERE operations.",C:"A column frequently in GROUP BY operations.",D:"A column frequently in AGGREGATE operations.",E:"A column frequently in JOIN operations."}, answer:["B","E"], explanation:"Clustering keys improve pruning for WHERE filters and JOIN conditions. ORDER BY, GROUP BY, and aggregations benefit less from clustering." },
  { id:31, domain:'D4: Performance', multi:false, text:"A warehouse suspends. When it resumes, the first query is slow. Why?", options:{A:"The result cache expired during suspension.",B:"The local SSD cache was cleared on suspend and data must be fetched from remote storage.",C:"The query was too large for memory.",D:"The result cache needed to be retrieved from another warehouse."}, answer:["B"], explanation:"SSD cache is wiped on suspend (cold start). Data must be re-fetched from remote storage. Result cache lives in Cloud Services and survives suspension." },
  { id:32, domain:'D4: Performance', multi:false, text:"Which query can benefit from the result cache?", options:{A:"SELECT customer_id FROM Customer WHERE city = 'Chicago'",B:"SELECT customer_id FROM Customer WHERE state = $VState",C:"SELECT UUID_STRING() FROM Customers WHERE state = 'AZ'",D:"SELECT customer_id FROM Customer WHERE tag = UUID_STRING()"}, answer:["A"], explanation:"Result cache requires identical query text + deterministic functions. A is deterministic. B uses session variable (text changes). C and D use UUID_STRING() (non-deterministic)." },
  { id:33, domain:'D4: Performance', multi:false, text:"When semi-structured data includes dates as string values, what Snowflake recommendation OPTIMIZES pruning and MINIMIZES storage?", options:{A:"Store the data as VARIANT.",B:"Store the data as ARRAY.",C:"Strip the outer array using TRY_PARSE_JSON.",D:"Flatten the key data into relational columns."}, answer:["D"], explanation:"Snowflake recommends flattening frequently queried date/timestamp fields into native relational columns. This enables micro-partition pruning and reduces storage vs strings inside VARIANT." },
  { id:34, domain:'D4: Performance', multi:false, text:"When unloading relational data to JSON, which function converts each row into a single VARIANT JSON object?", options:{A:"ARRAY_AGG",B:"OBJECT_CONSTRUCT",C:"PARSE_JSON",D:"TO_VARIANT"}, answer:["B"], explanation:"OBJECT_CONSTRUCT(*) converts each row into {col_name: value, ...} JSON. Used with COPY INTO @stage to unload as JSON." },
  { id:35, domain:'D4: Performance', multi:false, text:"A virtual warehouse was used for 5 minutes and 15 seconds then shut down. How many seconds is the customer billed for?", options:{A:"300 seconds",B:"315 seconds",C:"320 seconds",D:"360 seconds"}, answer:["B"], explanation:"Per-second billing with 60-second minimum. 5m15s = 315 seconds. Since 315 > 60, the exact 315 seconds is billed." },
  { id:36, domain:'D5: Sharing', multi:false, text:"What is true about Snowflake Secure Data Sharing?", options:{A:"Data is physically copied to the consumer account.",B:"Only views can be shared, not tables.",C:"Data is shared without copying, using Snowflake's metadata layer.",D:"Both accounts must be in different regions."}, answer:["C"], explanation:"Secure Data Sharing provides zero-copy access via metadata references. No data is copied. Tables and secure views can be shared." },
  { id:37, domain:'D5: Sharing', multi:true, text:"Which database objects can be shared with Secure Data Sharing? (Select TWO).", options:{A:"Secure views",B:"Materialized views",C:"External stages",D:"External tables",E:"Dynamic tables"}, answer:["A","D"], explanation:"Secure views and external tables can be shared. Standard views, materialized views, stages, and dynamic tables cannot be directly shared." },
  { id:38, domain:'D5: Sharing', multi:false, text:"What role is needed to create a Reader Account for a consumer who does not have a Snowflake account?", options:{A:"SYSADMIN",B:"ACCOUNTADMIN",C:"USERADMIN",D:"SECURITYADMIN"}, answer:["B"], explanation:"Only ACCOUNTADMIN can create Reader Accounts. The provider pays for all compute in the Reader Account." },
  { id:39, domain:'D5: Sharing', multi:false, text:"What privilege does a user need to receive or request data from the Snowflake Marketplace?", options:{A:"CREATE DATA EXCHANGE LISTING",B:"CREATE SHARE",C:"IMPORT SHARE",D:"IMPORTED PRIVILEGES"}, answer:["C"], explanation:"IMPORT SHARE privilege is required to get/install Marketplace listings. CREATE SHARE is for providers. IMPORTED PRIVILEGES grants access to shared DB objects." },
  { id:40, domain:'D5: Sharing', multi:false, text:"What happens when a table with a column referencing a sequence is cloned?", options:{A:"A new independent sequence is created for the clone.",B:"The clone references the same original sequence.",C:"The default is removed from the cloned table.",D:"The clone fails because sequences cannot be referenced in clones."}, answer:["B"], explanation:"The cloned table references the SAME original sequence. The sequence is NOT duplicated. Both tables share it. Validated via live SQL." },
];

const QUESTIONS_E02 = [
  { id:1, domain:'D1: Architecture', multi:false, text:"Which Snowflake feature allows automatic continuous loading from cloud storage WITHOUT requiring a user-managed warehouse?", options:{A:"Scheduled tasks with COPY INTO",B:"Snowpipe",C:"Dynamic tables",D:"Materialized views"}, answer:["B"], explanation:"Snowpipe uses serverless compute (not a user warehouse) for continuous auto-ingestion triggered by cloud event notifications or REST API." },
  { id:2, domain:'D1: Architecture', multi:false, text:"A sequence is used as a default value in a table. Two sessions call nextval concurrently. Are values guaranteed to be sequential with no gaps?", options:{A:"Yes, sequences always produce sequential, gap-free values.",B:"No, sequences guarantee uniqueness but not gap-free or ordered delivery.",C:"Yes, but only within the same warehouse.",D:"No, sequences produce random values."}, answer:["B"], explanation:"Snowflake sequences guarantee unique values but NOT gap-free or sequential across sessions. Values are allocated in batches, causing potential gaps." },
  { id:3, domain:'D1: Architecture', multi:false, text:"What is the key difference between a standard view and a secure view?", options:{A:"Secure views are faster because they are pre-computed.",B:"Secure views hide their SQL definition from non-owner roles.",C:"Standard views support JOINs; secure views do not.",D:"Secure views can only reference one table."}, answer:["B"], explanation:"Secure views hide their definition from non-owners, preventing data leakage. Standard views expose their SQL. Both support JOINs and multiple tables. MVs (not secure views) are pre-computed." },
  { id:4, domain:'D1: Architecture', multi:false, text:"A warehouse resumes, runs a query for 30 seconds, then suspends. How many seconds are billed?", options:{A:"30 seconds",B:"60 seconds",C:"90 seconds",D:"0 seconds (under 1 minute is free)"}, answer:["B"], explanation:"Per-second billing with 60-second minimum per resume. 30 < 60, so charged 60 seconds." },
  { id:5, domain:'D1: Architecture', multi:true, text:"Which TWO Snowflake features use serverless compute managed by Snowflake? (Select TWO).", options:{A:"Automatic Clustering",B:"User-created virtual warehouses",C:"Snowpipe",D:"Running SELECT queries",E:"User-Defined Functions"}, answer:["A","C"], explanation:"Automatic Clustering and Snowpipe use Snowflake-managed serverless compute. Warehouses, queries, and UDFs run on user-managed compute." },
  { id:6, domain:'D1: Architecture', multi:false, text:"What does a dynamic table provide that a materialized view cannot?", options:{A:"Automatic refresh.",B:"Support for JOINs and complex transformations.",C:"Pre-computed results for faster reads.",D:"Serverless maintenance."}, answer:["B"], explanation:"Dynamic tables support JOINs and complex transformations. MVs are limited to a single base table with no JOINs. Both auto-refresh and pre-compute." },
  { id:7, domain:'D1: Architecture', multi:false, text:"Which tool tests connectivity between a client and Snowflake, checking DNS, TLS, and OCSP?", options:{A:"SnowSQL",B:"Snowflake CLI (snow)",C:"SnowCD",D:"Snowsight"}, answer:["C"], explanation:"SnowCD (Connectivity Diagnostic) tests network connectivity. It does NOT execute queries. SnowSQL runs SQL. Snowflake CLI manages objects. Snowsight is the web UI." },
  { id:8, domain:'D1: Architecture', multi:false, text:"Storage billing in Snowflake is calculated based on what?", options:{A:"Per query execution.",B:"Monthly average of compressed data stored, including Time Travel and Fail-safe.",C:"A flat monthly rate regardless of data volume.",D:"Storage is included in compute credits."}, answer:["B"], explanation:"Storage is billed monthly based on the average amount of compressed data stored, including active data, Time Travel data, and Fail-safe data. Separate from compute." },
  { id:9, domain:'D1: Architecture', multi:false, text:"Cortex Analyst converts what into SQL queries?", options:{A:"Python DataFrames",B:"Natural language questions using a semantic model",C:"Stored procedure code",D:"Query Profile output"}, answer:["B"], explanation:"Cortex Analyst is a text-to-SQL service. It takes natural language questions and generates SQL using a semantic model (YAML) that describes tables, joins, and metrics." },
  { id:10, domain:'D1: Architecture', multi:false, text:"What happens when a task's WHEN condition evaluates to FALSE?", options:{A:"The task runs but processes zero rows.",B:"The task is skipped entirely and no compute is consumed.",C:"The task is automatically suspended.",D:"An error is logged to the task history."}, answer:["B"], explanation:"When WHEN evaluates to FALSE, the entire task run is skipped. No warehouse is resumed, no compute consumed. Common pattern: WHEN SYSTEM$STREAM_HAS_DATA()." },
  { id:11, domain:'D2: Security', multi:false, text:"Which Snowflake feature allows organizations to manage user identities via an external identity provider?", options:{A:"MFA",B:"SCIM",C:"Key-pair authentication",D:"Network policies"}, answer:["B"], explanation:"SCIM automates user and group provisioning/deprovisioning from an external IdP (Okta, Azure AD, etc.)." },
  { id:12, domain:'D2: Security', multi:false, text:"What privilege must be granted to a role so it can create tables in a specific schema?", options:{A:"USAGE on the schema",B:"CREATE TABLE on the schema",C:"OWNERSHIP of the schema",D:"INSERT on the schema"}, answer:["B"], explanation:"CREATE TABLE on the schema grants table creation ability. USAGE allows browsing. OWNERSHIP grants everything. The role also needs USAGE on the database and schema." },
  { id:13, domain:'D2: Security', multi:true, text:"How can ACCESS_HISTORY be used to review data governance? (Select TWO).", options:{A:"Identify queries run by a particular user.",B:"Identify access to roles given to a user.",C:"Identify SQL statements that failed to run.",D:"Identify objects that were modified by a query.",E:"Identify object dependencies."}, answer:["A","D"], explanation:"ACCESS_HISTORY tracks which user ran queries (A) and which objects were read/written/modified (D). Role grants use GRANTS_TO_USERS. Failed SQL uses QUERY_HISTORY. Dependencies use OBJECT_DEPENDENCIES." },
  { id:14, domain:'D2: Security', multi:false, text:"A column has a masking policy that allows role FINANCE. A user queries through a view that reads this column. The user's role is ANALYST. What do they see?", options:{A:"Unmasked data because views bypass masking.",B:"Masked data because the policy follows the column through views.",C:"An error because masking blocks view access.",D:"Unmasked data because the view owner has FINANCE role."}, answer:["B"], explanation:"Masking policies follow the column, not the object. Querying through a view still evaluates the policy against the querying role. ANALYST is not FINANCE, so data is masked." },
  { id:15, domain:'D2: Security', multi:false, text:"What is the effect of granting OPERATE privilege on a warehouse?", options:{A:"The role can execute queries on the warehouse.",B:"The role can resume, suspend, and abort queries on the warehouse.",C:"The role can resize the warehouse.",D:"The role can drop the warehouse."}, answer:["B"], explanation:"OPERATE = resume, suspend, abort queries. USAGE = execute queries. MODIFY = resize, change properties. OWNERSHIP = all + drop." },
  { id:16, domain:'D2: Security', multi:false, text:"Which edition is the MINIMUM required to use Dynamic Data Masking?", options:{A:"Standard",B:"Enterprise",C:"Business Critical",D:"Virtual Private Snowflake"}, answer:["B"], explanation:"Dynamic Data Masking requires Enterprise Edition or higher." },
  { id:17, domain:'D2: Security', multi:false, text:"Higher Snowflake editions impact which costs?", options:{A:"Only compute credit unit costs.",B:"Only storage unit costs.",C:"Both storage and compute unit costs.",D:"Neither. Pricing is the same across all editions."}, answer:["C"], explanation:"Higher editions have higher unit costs for BOTH storage and compute. Standard is cheapest per unit. Business Critical and VPS are more expensive per TB and per credit." },
  { id:18, domain:'D3: Loading', multi:false, text:"What is the primary security benefit of using a STORAGE INTEGRATION for an external stage?", options:{A:"It encrypts data files in the bucket.",B:"It grants temporary unload permissions.",C:"It avoids storing hard-coded credentials in the stage definition.",D:"It deploys stored procedures from a Git repository."}, answer:["C"], explanation:"Storage integrations use IAM trust relationships. No AWS keys or secrets are stored in the stage definition itself." },
  { id:19, domain:'D3: Loading', multi:false, text:"What does the MATCH_BY_COLUMN_NAME option do in COPY INTO?", options:{A:"Loads only columns that exist in both file and table.",B:"Matches file columns to table columns by name instead of position.",C:"Validates column name uniqueness before loading.",D:"Renames columns to match the target table."}, answer:["B"], explanation:"MATCH_BY_COLUMN_NAME matches by name not ordinal position. Useful for Parquet, Avro, ORC where column order may differ." },
  { id:20, domain:'D3: Loading', multi:false, text:"What does a directory table on a stage provide?", options:{A:"The data content of all files.",B:"File-level metadata: URLs, sizes, last-modified timestamps.",C:"The schema of the files.",D:"Access control lists for each file."}, answer:["B"], explanation:"Directory tables provide file-level metadata (not content). Useful for managing unstructured data and building file catalogs." },
  { id:21, domain:'D3: Loading', multi:false, text:"A COPY INTO uses ON_ERROR = 'SKIP_FILE_3'. A file has exactly 2 parsing errors. What happens?", options:{A:"The file is skipped because it has errors.",B:"The file is loaded because 2 < 3 (threshold not reached).",C:"Only the first 3 rows are loaded.",D:"The entire COPY aborts."}, answer:["B"], explanation:"SKIP_FILE_n skips when errors >= n. Since 2 < 3, the file IS loaded (bad rows handled per other settings). With 3+ errors, it would be skipped." },
  { id:22, domain:'D3: Loading', multi:true, text:"Which TWO are valid stage file operations? (Select TWO).", options:{A:"LIST @my_stage (view files)",B:"REMOVE @my_stage/file.csv (delete files)",C:"RENAME @my_stage/old.csv TO new.csv",D:"MOVE @my_stage/file.csv TO @other_stage",E:"EDIT @my_stage/file.csv"}, answer:["A","B"], explanation:"LIST (LS) and REMOVE (RM) are the only file operations. No RENAME, MOVE, or EDIT commands for staged files." },
  { id:23, domain:'D3: Loading', multi:false, text:"A stage has FILE_FORMAT set to pipe-delimited CSV. A COPY INTO command specifies FILE_FORMAT = (TYPE=CSV FIELD_DELIMITER=','). Which delimiter is used?", options:{A:"Pipe (stage format wins).",B:"Comma (COPY inline format overrides stage format).",C:"An error for conflicting formats.",D:"System default (tab)."}, answer:["B"], explanation:"File format precedence: COPY INTO inline > stage-level > schema/database defaults. Inline always wins." },
  { id:24, domain:'D3: Loading', multi:false, text:"Snowpipe Streaming (via the Ingest SDK) differs from standard Snowpipe in what key way?", options:{A:"Streaming uses a user warehouse; standard is serverless.",B:"Streaming inserts rows directly without staging files.",C:"Standard supports JSON only; Streaming supports all formats.",D:"They are identical services."}, answer:["B"], explanation:"Snowpipe Streaming inserts rows directly via SDK without intermediate files. Standard Snowpipe loads files from stages." },
  { id:25, domain:'D3: Loading', multi:false, text:"A Kafka connector sends data to Snowflake. What authentication method does it use?", options:{A:"Username and password",B:"OAuth tokens",C:"Key-pair (RSA) authentication",D:"SAML 2.0 SSO"}, answer:["C"], explanation:"The Snowflake Kafka Connector uses key-pair (RSA) authentication for secure programmatic access." },
  { id:26, domain:'D3: Loading', multi:false, text:"Which function can be used to examine the structure of files in a stage before loading?", options:{A:"DESCRIBE STAGE",B:"INFER_SCHEMA",C:"VALIDATE",D:"SHOW FILE FORMATS"}, answer:["B"], explanation:"INFER_SCHEMA analyzes files in a stage and returns detected column names, types, and order. VALIDATE checks errors after loading. DESCRIBE shows stage properties." },
  { id:27, domain:'D4: Performance', multi:false, text:"A complex 8-table JOIN query scans all partitions. The Query Profile shows inefficient pruning. What is the root cause?", options:{A:"The warehouse is too small.",B:"Pruning is not being performed efficiently because filter columns are not aligned with data layout.",C:"Too many JOINs prevent pruning.",D:"The result cache has expired."}, answer:["B"], explanation:"All partitions scanned = pruning failure. Filter columns are not aligned with clustering. Fix: add clustering keys on frequently filtered columns." },
  { id:28, domain:'D4: Performance', multi:false, text:"A standard warehouse has increasing queuing at the same time each day due to many concurrent users. Which is the MOST cost-effective solution?", options:{A:"Scale up the warehouse.",B:"Run the warehouse in Auto-scale mode.",C:"Run the warehouse in Maximized mode.",D:"Use a Snowpark-optimized warehouse."}, answer:["B"], explanation:"Auto-scale (multi-cluster, auto-scaling) adds clusters during peak and removes them when demand drops. Most cost-effective for predictable daily spikes. Maximized runs all clusters always (expensive)." },
  { id:29, domain:'D4: Performance', multi:false, text:"Which table characteristic will PREVENT the Query Acceleration Service from accelerating queries?", options:{A:"The table has a large number of micro-partitions.",B:"The table has Search Optimization configured.",C:"A clustering key is defined on a GEOMETRY column.",D:"The table was created with CREATE TABLE AS SELECT."}, answer:["C"], explanation:"QAS does not support tables with clustering keys on GEOMETRY columns. Large partition counts, SOS, and CTAS tables do not block QAS." },
  { id:30, domain:'D4: Performance', multi:true, text:"Which TWO scenarios benefit MOST from a clustering key? (Select TWO).", options:{A:"Filtering on a column in ORDER BY frequently.",B:"Filtering on a column in WHERE frequently.",C:"Filtering on a column in GROUP BY frequently.",D:"Filtering on a column in AGGREGATE operations.",E:"Filtering on a column in JOIN conditions frequently."}, answer:["B","E"], explanation:"Clustering improves pruning for WHERE filters and JOIN conditions by aligning data with min/max metadata." },
  { id:31, domain:'D4: Performance', multi:false, text:"An ETL pipeline runs a single complex transformation spilling to REMOTE storage. No queuing. What should you do?", options:{A:"Add more clusters (scale out).",B:"Enable Query Acceleration Service.",C:"Increase the warehouse size (scale up).",D:"Add a clustering key."}, answer:["C"], explanation:"Single query + remote spilling + no queuing = need more memory = scale UP. Multi-cluster does not help a single query. QAS could help but the root cause is insufficient memory. Clustering helps pruning, not spilling." },
  { id:32, domain:'D4: Performance', multi:false, text:"How does query pruning optimize performance in Snowflake?", options:{A:"By terminating queries after a timeout.",B:"By pulling results from the result cache.",C:"By removing unnecessary query clauses.",D:"By preventing unnecessary scanning of micro-partitions."}, answer:["D"], explanation:"Pruning uses micro-partition metadata (min/max) to skip partitions that cannot contain matching rows. It reduces data scanned, not query structure." },
  { id:33, domain:'D4: Performance', multi:false, text:'A user runs SELECT col1:city::VARCHAR FROM my_table where col1 is VARIANT containing {"city":"Denver"}. What is returned?', options:{A:'"Denver" (with quotes)',B:"Denver (without quotes)",C:"NULL",D:"An error"}, answer:["B"], explanation:"Casting with ::VARCHAR strips the JSON quotes. Without the cast, you would get \"Denver\" with quotes. The cast returns the clean string." },
  { id:34, domain:'D4: Performance', multi:false, text:"Which SQL clause filters on window function results without requiring a subquery?", options:{A:"HAVING",B:"WHERE",C:"QUALIFY",D:"FILTER"}, answer:["C"], explanation:"QUALIFY filters after window functions. Example: QUALIFY ROW_NUMBER() OVER (...) = 1. HAVING filters after GROUP BY aggregates." },
  { id:35, domain:'D4: Performance', multi:false, text:"A multi-cluster warehouse has 2 active clusters, each X-Large (16 credits/hr), running for 30 minutes. Total credits consumed?", options:{A:"8 credits",B:"16 credits",C:"32 credits",D:"64 credits"}, answer:["B"], explanation:"2 clusters x 16 credits/hr x 0.5 hours = 16 credits. Multi-cluster multiplies credits by active cluster count." },
  { id:36, domain:'D5: Sharing', multi:false, text:"How does Snowflake's data sharing work with Reader Accounts?", options:{A:"The reader must have their own Snowflake subscription.",B:"The provider provisions and pays for a reader account so non-Snowflake users can access shared data.",C:"Reader accounts can only view metadata, not data.",D:"Reader accounts are limited to 1 TB of shared data."}, answer:["B"], explanation:"Reader Accounts are created by the provider for consumers without Snowflake. Provider pays for all compute. Despite the name, readers CAN create warehouses, tables, etc." },
  { id:37, domain:'D5: Sharing', multi:true, text:"Which TWO objects can be shared via Snowflake Secure Data Sharing? (Select TWO).", options:{A:"Secure views",B:"Secure UDFs",C:"Standard (non-secure) views",D:"Stored procedures",E:"Warehouses"}, answer:["A","B"], explanation:"Secure views AND secure UDFs can be shared. Standard views are rejected. Stored procedures and warehouses cannot be shared." },
  { id:38, domain:'D5: Sharing', multi:false, text:"A Direct Share can share data with consumers in which scope?", options:{A:"Any Snowflake account in any region.",B:"Only accounts within the same region.",C:"Only accounts within the same cloud provider.",D:"Only accounts within the same organization."}, answer:["B"], explanation:"Direct Shares are same-region only. For cross-region sharing, use Listings with Cross-Cloud Auto-Fulfillment." },
  { id:39, domain:'D5: Sharing', multi:false, text:"When working with high-churn dimension tables, what is the recommended approach to manage costs?", options:{A:"Set Time Travel to 90 days for maximum protection.",B:"Make tables transient and back up daily using cloning to a permanent table.",C:"Increase warehouse size to handle the churn.",D:"Disable Time Travel entirely and rely on Fail-safe."}, answer:["B"], explanation:"Transient tables eliminate Fail-safe costs. Daily cloning provides backup. Clone is zero-copy so backup cost is minimal. This balances cost savings with protection. From real exam." },
  { id:40, domain:'D5: Sharing', multi:false, text:"A provider adds a new column to a table that is already included in a share. What must the consumer do?", options:{A:"Recreate the shared database.",B:"Run ALTER DATABASE REFRESH.",C:"Nothing. The new column is visible automatically.",D:"Request the provider to re-grant access."}, answer:["C"], explanation:"Schema changes (new columns, new tables added to share) are automatically visible to consumers. No action needed." },
];

const QUESTIONS_E03 = [
  { id:1, domain:'D1: Architecture', multi:false, text:"A user notices that COUNT(*) on a 5 billion row table returns instantly without the warehouse resuming. Which component served this result?", options:{A:"The result cache from a previous identical query.",B:"The metadata cache in the Cloud Services layer, which stores row counts.",C:"The local SSD cache on the warehouse nodes.",D:"A materialized view that pre-computed the count."}, answer:["B"], explanation:"Cloud Services stores metadata including row counts, min/max, and distinct counts per micro-partition. Simple metadata queries like COUNT(*) can be answered without a warehouse." },
  { id:2, domain:'D1: Architecture', multi:false, text:"An X-Small warehouse resumes, runs queries for 3 minutes 20 seconds, then two more queries for 45 seconds before suspending. Total billed seconds?", options:{A:"200 seconds (3m20s only, second batch free)",B:"245 seconds (200 + 45, per-second billing for both)",C:"300 seconds (rounded to 5 minutes)",D:"260 seconds (200 + 60-second minimum for second batch)"}, answer:["B"], explanation:"The warehouse stays running between queries (it did not suspend between them). Total continuous runtime = 200 + 45 = 245 seconds. The 60s minimum only applies per RESUME, not per query." },
  { id:3, domain:'D1: Architecture', multi:false, text:"A developer adds UNIQUE and NOT NULL constraints to a Snowflake table. What enforcement does Snowflake provide?", options:{A:"Both constraints are fully enforced on every INSERT and UPDATE.",B:"NOT NULL is enforced; UNIQUE is informational only (duplicates allowed).",C:"Neither constraint is enforced; both are informational only.",D:"UNIQUE is enforced; NOT NULL is informational only."}, answer:["B"], explanation:"Snowflake enforces NOT NULL but does NOT enforce UNIQUE, PRIMARY KEY, or FOREIGN KEY constraints. Those are informational/metadata only for BI tools and documentation." },
  { id:4, domain:'D1: Architecture', multi:true, text:"A data team needs to decide between a materialized view and a dynamic table. Which TWO are limitations of materialized views? (Select TWO).", options:{A:"Cannot include JOINs (single base table only).",B:"Cannot be auto-refreshed.",C:"Cannot include aggregate functions.",D:"Cannot include UDFs in the definition.",E:"Require Standard Edition (no edition restriction)."}, answer:["A","D"], explanation:"MVs cannot include JOINs (single table) and cannot include UDFs. They CAN include aggregates and DO auto-refresh. They require Enterprise+." },
  { id:5, domain:'D1: Architecture', multi:false, text:"A team uses separate warehouses for ETL, BI dashboards, and ad-hoc analysis. What best practice does this represent?", options:{A:"Cost minimization through shared compute.",B:"Workload isolation to prevent different teams from impacting each other.",C:"Data replication across availability zones.",D:"Auto-scaling optimization."}, answer:["B"], explanation:"Dedicated warehouses per workload type prevent one team's heavy queries from causing queuing or resource contention for another. This is Snowflake's recommended workload management practice." },
  { id:6, domain:'D1: Architecture', multi:false, text:"Which Snowflake edition is required for Search Optimization Service?", options:{A:"All editions",B:"Enterprise and above",C:"Business Critical and above",D:"Virtual Private Snowflake only"}, answer:["B"], explanation:"Search Optimization Service requires Enterprise Edition or higher, same as materialized views, clustering, and dynamic data masking." },
  { id:7, domain:'D1: Architecture', multi:false, text:"A Streamlit in Snowflake app accesses a table. Whose role and warehouse does it use for data access?", options:{A:"The app creator's role and a dedicated serverless pool.",B:"The app viewer's role and warehouse.",C:"ACCOUNTADMIN role and the account's default warehouse.",D:"A shared application role with read-only access."}, answer:["B"], explanation:"SiS apps run using the VIEWER's role and warehouse for data access. This means different viewers may see different data based on their role's privileges." },
  { id:8, domain:'D1: Architecture', multi:false, text:"A child task in a DAG does not have a SCHEDULE defined. How is it triggered?", options:{A:"It inherits the parent's schedule automatically.",B:"It runs when its predecessor task(s) complete successfully.",C:"It must be triggered manually with EXECUTE TASK.",D:"It runs continuously in a loop."}, answer:["B"], explanation:"In a task DAG, only the root task has a SCHEDULE. Child tasks fire when their predecessor(s) complete. Children cannot have their own schedules." },
  { id:9, domain:'D1: Architecture', multi:false, text:"Which Snowflake ML function provides built-in time-series forecasting without external frameworks?", options:{A:"PREDICT()",B:"FORECAST()",C:"TIME_SERIES_MODEL()",D:"ML_TRAIN()"}, answer:["B"], explanation:"FORECAST is a built-in Snowflake ML function for time-series prediction. ANOMALY_DETECTION is for outlier detection. Both are serverless and require no external ML frameworks." },
  { id:10, domain:'D1: Architecture', multi:false, text:"How do micro-partitions enable query pruning?", options:{A:"By storing user-defined indexes on frequently queried columns.",B:"By maintaining min/max metadata per column, allowing Snowflake to skip partitions that cannot match filters.",C:"By compressing data so less needs to be scanned.",D:"By distributing data evenly across all warehouse nodes."}, answer:["B"], explanation:"Each micro-partition stores min/max values, null counts, and distinct counts per column. The optimizer uses this metadata to skip (prune) partitions that cannot contain matching rows." },
  { id:11, domain:'D2: Security', multi:false, text:"A new custom role DATA_TEAM is created but not granted to SYSADMIN. An admin using ACCOUNTADMIN tries to query a table owned by DATA_TEAM. What happens?", options:{A:"ACCOUNTADMIN can query any table in the account.",B:"The query fails because ACCOUNTADMIN does not inherit DATA_TEAM's privileges without the hierarchy link.",C:"The query succeeds but returns masked data.",D:"Snowflake automatically grants the role to SYSADMIN."}, answer:["B"], explanation:"If a custom role is not in SYSADMIN's hierarchy, even ACCOUNTADMIN cannot access its objects. Best practice: always grant custom roles to SYSADMIN." },
  { id:12, domain:'D2: Security', multi:false, text:"An admin wants to track which specific COLUMNS were read by analyst queries last month. Which ACCOUNT_USAGE view provides this?", options:{A:"QUERY_HISTORY (contains SQL text but not column-level detail).",B:"ACCESS_HISTORY (tracks column-level data access per query).",C:"LOGIN_HISTORY (tracks authentication events).",D:"OBJECT_DEPENDENCIES (tracks object references, not query access)."}, answer:["B"], explanation:"ACCESS_HISTORY provides column-level tracking: DIRECT_OBJECTS_ACCESSED and BASE_OBJECTS_ACCESSED with column detail. QUERY_HISTORY has query text but not column granularity. OBJECT_DEPENDENCIES shows object-to-object references." },
  { id:13, domain:'D2: Security', multi:false, text:"A user connects to Snowflake using a Kafka connector for streaming data ingestion. Which authentication method does this connector require?", options:{A:"Username and password.",B:"SAML 2.0 SSO.",C:"Key-pair (RSA) authentication.",D:"OAuth bearer token."}, answer:["C"], explanation:"The Snowflake Kafka Connector requires key-pair (RSA) authentication. SAML is for browser SSO. OAuth is for custom apps. Username/password is not recommended for programmatic connectors." },
  { id:14, domain:'D2: Security', multi:true, text:"A security audit requires knowing who has what access. Which TWO SHOW GRANTS variants would you use? (Select TWO).", options:{A:"SHOW GRANTS ON TABLE my_table (shows who has access to this table)",B:"SHOW GRANTS TO ROLE analyst (shows what the analyst role can do)",C:"SHOW GRANTS FOR USER jdoe (shows all user privileges)",D:"SHOW GRANTS BY DATABASE (shows all grants in a database)",E:"SHOW GRANTS IN SCHEMA (shows schema-level grants)"}, answer:["A","B"], explanation:"SHOW GRANTS ON <object> = who has access. SHOW GRANTS TO ROLE = what can this role do. Also: SHOW GRANTS OF ROLE = who has this role. FOR USER and BY DATABASE do not exist." },
  { id:15, domain:'D2: Security', multi:false, text:"A row access policy on a sales table restricts rows by region. An analyst not mentioned in the policy queries the table. The policy's CASE has no ELSE clause. How many rows are returned?", options:{A:"All rows (unmentioned roles are not restricted).",B:"Zero rows (CASE returns NULL, treated as FALSE).",C:"An error (missing ELSE causes a syntax failure).",D:"Rows from all regions (default is TRUE when no match)."}, answer:["B"], explanation:"A CASE with no matching WHEN and no ELSE returns NULL. In a boolean context (row access), NULL = FALSE = zero rows. No role bypasses this, not even ACCOUNTADMIN." },
  { id:16, domain:'D2: Security', multi:false, text:"What is the purpose of a notification integration in Snowflake?", options:{A:"To send push notifications to the Snowsight mobile app.",B:"To deliver alert and error notifications via email or webhooks.",C:"To notify users when their queries complete.",D:"To integrate with SMS messaging services."}, answer:["B"], explanation:"Notification integrations deliver messages via email or webhooks (Slack, PagerDuty, etc.) for alerts, budget notifications, and Snowpipe error notifications." },
  { id:17, domain:'D2: Security', multi:false, text:"Which ACCOUNT_USAGE view would you query to find object-to-object references (e.g., which views depend on which tables)?", options:{A:"ACCESS_HISTORY",B:"QUERY_HISTORY",C:"OBJECT_DEPENDENCIES",D:"GRANTS_TO_ROLES"}, answer:["C"], explanation:"OBJECT_DEPENDENCIES tracks object references: which views reference which tables, which procedures reference which objects. ACCESS_HISTORY tracks query-level data access, not structural dependencies." },
  { id:18, domain:'D3: Loading', multi:false, text:"A data engineer loads a file via Snowpipe. 16 days later, the identical file arrives again. What happens?", options:{A:"Skipped (Snowpipe metadata retained for 64 days).",B:"Loaded again (Snowpipe metadata retention is 14 days, 16 > 14).",C:"An error is raised for duplicate detection.",D:"Skipped permanently (metadata never expires for Snowpipe)."}, answer:["B"], explanation:"Snowpipe retains load metadata for 14 days. Since 16 > 14, the metadata expired and the file is treated as new. Bulk COPY retention is 64 days (different!)." },
  { id:19, domain:'D3: Loading', multi:false, text:"COPY INTO uses ON_ERROR = 'CONTINUE' and PURGE = TRUE. A file has 100 rows, 3 have errors. After loading, what happens to the file?", options:{A:"The file remains because it had errors.",B:"The file is purged because it was processed (97 valid rows loaded).",C:"Only the 3 error rows are removed from the file.",D:"The file is moved to a quarantine folder."}, answer:["B"], explanation:"With CONTINUE, bad rows are skipped but the file is considered processed. PURGE = TRUE deletes files that were processed, even if partially. 97 rows load and the file is purged." },
  { id:20, domain:'D3: Loading', multi:false, text:"A user wants to see what files exist in an internal stage. Which command should they use?", options:{A:"DESCRIBE STAGE @my_stage",B:"SELECT * FROM @my_stage",C:"LIST @my_stage",D:"SHOW FILES IN @my_stage"}, answer:["C"], explanation:"LIST (or LS) shows files in a stage. DESCRIBE shows stage properties (not files). SELECT queries data inside files. SHOW FILES does not exist." },
  { id:21, domain:'D3: Loading', multi:true, text:"Which TWO COPY INTO parameters help handle files where column counts or sizes don't match the target table? (Select TWO).", options:{A:"TRUNCATECOLUMNS (truncate oversized strings instead of erroring)",B:"ERROR_ON_COLUMN_COUNT_MISMATCH (error if column counts differ)",C:"PURGE (delete files after load)",D:"FORCE (reload already-loaded files)",E:"PATTERN (regex file filter)"}, answer:["A","B"], explanation:"TRUNCATECOLUMNS handles oversized strings. ERROR_ON_COLUMN_COUNT_MISMATCH handles column count differences. PURGE, FORCE, and PATTERN handle different aspects." },
  { id:22, domain:'D3: Loading', multi:false, text:"A stream on TABLE_A has not been consumed for 30 days. The table's DATA_RETENTION_TIME_IN_DAYS is 14 and MAX_DATA_EXTENSION_TIME_IN_DAYS is 14. Is the stream stale?", options:{A:"Yes, stale after 14 days (retention only).",B:"No, the stream is valid for 28 days (sum of both).",C:"Yes, stale after 14 days (the greater of both values, which are equal).",D:"No, streams never go stale."}, answer:["C"], explanation:"Staleness = GREATER of (retention, max_extension) = GREATER(14, 14) = 14 days. 30 > 14, so the stream is stale. Must DROP and RECREATE. Note: it is the GREATER, not the SUM." },
  { id:23, domain:'D3: Loading', multi:false, text:"What does the GET command do in Snowflake?", options:{A:"Uploads files from local machine to an internal stage.",B:"Downloads files from an internal stage to the local filesystem.",C:"Retrieves query results from the result cache.",D:"Gets the DDL definition of a database object."}, answer:["B"], explanation:"GET downloads files from an INTERNAL stage to local filesystem. PUT does the upload. Both require SnowSQL or drivers (not Snowsight). GET_DDL is a separate function." },
  { id:24, domain:'D3: Loading', multi:false, text:"A COPY INTO command uses ON_ERROR = 'SKIP_FILE_5'. A file has 4 parsing errors. What happens to this file?", options:{A:"The file is skipped (it has errors).",B:"The file is loaded (4 < 5, threshold not reached).",C:"Only the first 5 rows are loaded.",D:"The COPY aborts entirely."}, answer:["B"], explanation:"SKIP_FILE_n skips only when error count >= n. Since 4 < 5, the file is loaded. Bad rows are handled per the error behavior. With 5+ errors, the file would be skipped." },
  { id:25, domain:'D3: Loading', multi:false, text:"A data pipeline needs to automatically detect the column names and types of Parquet files on a stage before creating the target table. Which function helps?", options:{A:"VALIDATE()",B:"DESCRIBE STAGE",C:"INFER_SCHEMA()",D:"SHOW COLUMNS"}, answer:["C"], explanation:"INFER_SCHEMA analyzes files on a stage and returns detected column names, types, and order. VALIDATE checks errors after loading. DESCRIBE shows stage properties." },
  { id:26, domain:'D3: Loading', multi:false, text:"A Git integration in Snowflake synchronizes what into a Snowflake stage?", options:{A:"Table data from a remote database.",B:"Code files (SQL, Python) from a Git repository.",C:"Docker container images for Snowpark.",D:"Machine learning model artifacts."}, answer:["B"], explanation:"Git integration syncs code files (SQL scripts, Python, etc.) from a Git repo into a Snowflake stage for use in procedures, Notebooks, and Streamlit apps." },
  { id:27, domain:'D4: Performance', multi:false, text:"An analyst's ad-hoc query scans a 10 TB table and takes 20 minutes. Most other queries on this warehouse finish in under 30 seconds. Which optimization is BEST for this outlier pattern?", options:{A:"Add a clustering key.",B:"Enable Query Acceleration Service.",C:"Create a materialized view.",D:"Increase the warehouse to 4X-Large permanently."}, answer:["B"], explanation:"QAS is designed for outlier queries that use 10-100x more resources than typical. It offloads scan portions to serverless compute. Permanent upsizing wastes credits for the 95% of queries that are already fast." },
  { id:28, domain:'D4: Performance', multi:false, text:"A table is clustered on (country, order_date). A query filters: WHERE order_date = '2026-01-15'. How effective is pruning?", options:{A:"Fully effective, same as filtering on country.",B:"Partially effective, but less than filtering on the leading column (country).",C:"Not effective at all.",D:"It depends on the warehouse size."}, answer:["B"], explanation:"Filtering on a non-leading column (order_date is second) provides SOME pruning but less than filtering on country (first) or both. Put the most commonly filtered, lower-cardinality column first." },
  { id:29, domain:'D4: Performance', multi:false, text:"Two users run the exact same SELECT query. User A gets results in 50ms. User B gets results in 8 seconds. The table has a masking policy. Why the difference?", options:{A:"User B has a slower network connection.",B:"The result cache is role-specific when policies exist, so User B's role has a different cached result.",C:"User B's warehouse is smaller.",D:"User A ran the query more recently."}, answer:["B"], explanation:"When row access or masking policies exist, the result cache is role-specific. Different roles may see different data, so cached results are NOT shared across roles. User A got a cache hit for their role; User B did not." },
  { id:30, domain:'D4: Performance', multi:false, text:"A single ETL job processes a massive aggregation and the Query Profile shows 'Bytes Spilled to Remote Storage'. No other users are on the warehouse. What should you do?", options:{A:"Add more clusters (scale out).",B:"Increase the warehouse size (scale up) for more memory.",C:"Enable ECONOMY scaling policy.",D:"Add a clustering key to the source table."}, answer:["B"], explanation:"Single query + remote spilling + no concurrency = need more memory = scale UP. No queuing means multi-cluster is unnecessary. Key signal: 'single job' + 'no other users' = scale up, not out." },
  { id:31, domain:'D4: Performance', multi:true, text:"Which TWO functions produce approximate results for faster performance on large datasets? (Select TWO).", options:{A:"APPROXIMATE_COUNT_DISTINCT()",B:"COUNT(DISTINCT)",C:"HASH_AGG()",D:"HLL()",E:"SUM()"}, answer:["A","D"], explanation:"APPROXIMATE_COUNT_DISTINCT (and its alias HLL) use HyperLogLog for fast cardinality estimation with a small error margin. COUNT(DISTINCT), HASH_AGG, and SUM are exact." },
  { id:32, domain:'D4: Performance', multi:false, text:"A developer writes: SELECT name, salary, RANK() OVER (PARTITION BY dept ORDER BY salary DESC) AS rnk FROM employees QUALIFY rnk <= 3. What does this return?", options:{A:"All employees sorted by salary.",B:"The top 3 highest-paid employees per department.",C:"Exactly 3 rows from the entire table.",D:"An error because QUALIFY cannot reference an alias."}, answer:["B"], explanation:"QUALIFY filters window function results. RANK() partitioned by dept, ordered by salary DESC, filtered to <= 3 returns the top 3 per department. QUALIFY CAN reference column aliases." },
  { id:33, domain:'D4: Performance', multi:false, text:"LATERAL FLATTEN(input => data:items, OUTER => TRUE) is used on a row where data:items is NULL. What happens?", options:{A:"The row is excluded from results (default behavior without OUTER).",B:"The row appears with NULL values in the flattened columns.",C:"An error is raised.",D:"The NULL is converted to an empty array."}, answer:["B"], explanation:"OUTER => TRUE preserves rows with NULL/empty arrays, outputting NULLs in flattened columns (like LEFT JOIN). Without OUTER, NULL rows would be excluded." },
  { id:34, domain:'D4: Performance', multi:false, text:"A query needs the previous row's value for comparison. Which window function retrieves a value from the preceding row?", options:{A:"FIRST_VALUE()",B:"LAG()",C:"LEAD()",D:"NTH_VALUE()"}, answer:["B"], explanation:"LAG() accesses the previous row's value. LEAD() accesses the next row. FIRST_VALUE returns the first in the window. NTH_VALUE returns the nth value." },
  { id:35, domain:'D4: Performance', multi:false, text:"What is the difference between VALIDATE() and VALIDATION_MODE in the context of data loading?", options:{A:"They are the same feature with different names.",B:"VALIDATION_MODE is a COPY parameter (dry-run, no load). VALIDATE() is a function that reviews errors from a PREVIOUS load.",C:"VALIDATE() runs before loading. VALIDATION_MODE runs after.",D:"VALIDATE() checks table structure. VALIDATION_MODE checks file contents."}, answer:["B"], explanation:"VALIDATION_MODE in COPY INTO = dry-run, no data loaded, returns errors. VALIDATE(table, job_id) = after-the-fact review of errors from an already-executed COPY. Different timing, different purpose." },
  { id:36, domain:'D5: Sharing', multi:false, text:"A provider wants to share data with a consumer in a different cloud region. Direct Share does not work. What should they use?", options:{A:"Database replication only.",B:"A Listing with Cross-Cloud Auto-Fulfillment.",C:"A Reader Account in the consumer's region.",D:"An external stage pointing to the consumer's cloud storage."}, answer:["B"], explanation:"Direct Shares are same-region only. Listings with Auto-Fulfillment automatically replicate data to the consumer's region/cloud. Database replication works but requires more manual setup." },
  { id:37, domain:'D5: Sharing', multi:false, text:"A consumer creates a database from a share. They try to run INSERT INTO shared_table VALUES (1,'test'). What happens?", options:{A:"The insert succeeds.",B:"The insert fails because shared data is read-only.",C:"The insert succeeds but is not visible to the provider.",D:"The insert is queued for provider approval."}, answer:["B"], explanation:"Shared data is always read-only for consumers. No INSERT, UPDATE, DELETE, MERGE, or CLONE. To get a writable copy, use CREATE TABLE AS SELECT." },
  { id:38, domain:'D5: Sharing', multi:true, text:"A Reader Account consumer wants to work with shared data. Which TWO things CAN they do? (Select TWO).", options:{A:"Create a virtual warehouse to run queries.",B:"Create local tables to join with shared data.",C:"Create outbound shares to share data with others.",D:"Access the Snowflake Marketplace.",E:"Create pipes for data ingestion."}, answer:["A","B"], explanation:"Reader Accounts CAN create warehouses and tables (provider pays). They CANNOT create shares, pipes, stages, or access the Marketplace." },
  { id:39, domain:'D5: Sharing', multi:false, text:"A permanent table has DATA_RETENTION_TIME_IN_DAYS = 3 on Enterprise Edition. The table is dropped. Can it be recovered 2 days later?", options:{A:"No, dropped tables cannot be recovered.",B:"Yes, using UNDROP TABLE within the 3-day Time Travel period.",C:"Only by contacting Snowflake Support.",D:"Only if the table was cloned before dropping."}, answer:["B"], explanation:"UNDROP TABLE works within the Time Travel retention period. 2 days < 3 days = within retention. After 3 days, it enters Fail-safe (Support only)." },
  { id:40, domain:'D5: Sharing', multi:false, text:"A company wants to list data on the Snowflake Marketplace for all customers to discover. What type of listing and what approval is needed?", options:{A:"Private listing, no approval needed.",B:"Public listing, Snowflake reviews and approves before it goes live.",C:"Public listing, immediately visible to all.",D:"Private listing, Snowflake approval required."}, answer:["B"], explanation:"Public listings require Snowflake review before becoming visible on the Marketplace. Private listings are available immediately to specified accounts without review." },
];

const QUESTIONS_E04 = [
  { id:1, domain:'D1: Architecture', multi:false, text:"A COUNT(*) query on a 500-billion-row table returns instantly without consuming any warehouse credits. Which Snowflake component made this possible?", options:{A:"SSD cache on the compute nodes",B:"Metadata cache in the Cloud Services layer",C:"Result cache from a prior identical query",D:"Search Optimization Service pre-computed the count"}, answer:["B"], explanation:"The metadata cache stores row counts, min/max, null counts, and distinct counts per micro-partition. COUNT(*) is resolved from metadata alone, requiring no warehouse. SSD cache requires a running warehouse. Result cache needs a prior identical query. SOS does not pre-compute counts." },
  { id:2, domain:'D1: Architecture', multi:false, text:"Your company uses Snowflake Standard Edition. The data team requests dynamic data masking on salary columns. What must happen first?", options:{A:"Create a masking policy and attach it to the column",B:"Upgrade to Enterprise Edition or higher",C:"Enable Tri-Secret Secure on the account",D:"Grant the SECURITYADMIN role to the data team lead"}, answer:["B"], explanation:"Dynamic data masking requires Enterprise Edition or higher. Standard Edition does not support masking policies. Tri-Secret Secure is Business Critical+ and unrelated to masking. Granting SECURITYADMIN alone does not enable the feature." },
  { id:3, domain:'D1: Architecture', multi:false, text:"A developer writes a UDF that attempts to run ALTER TABLE inside it. What happens?", options:{A:"The ALTER TABLE executes successfully inside the UDF",B:"The UDF compiles but the ALTER TABLE is silently skipped",C:"The UDF fails because UDFs cannot execute DDL or DML statements",D:"The UDF succeeds only if the caller has OWNERSHIP on the table"}, answer:["C"], explanation:"UDFs return scalar or tabular values and CANNOT execute DDL or DML. Only stored procedures (called with CALL) can execute DDL/DML. UDFs are used in expressions like SELECT or WHERE." },
  { id:4, domain:'D1: Architecture', multi:true, text:"Which TWO statements about Snowflake sequences are correct? (Select TWO).", options:{A:"Sequences guarantee gap-free, consecutive values",B:"Sequences generate unique values but gaps are possible",C:"Sequences guarantee values are returned in order across concurrent sessions",D:"Sequences are NOT duplicated when a table referencing them is cloned",E:"Sequences automatically reset to 1 when the referencing table is truncated"}, answer:["B","D"], explanation:"Sequences generate unique values but are NOT gap-free and NOT ordered across sessions. When a table with a sequence default is cloned, both tables share the SAME original sequence (not duplicated). Sequences do not reset on TRUNCATE." },
  { id:5, domain:'D1: Architecture', multi:false, text:"A team needs to run complex JOINs that auto-refresh on a schedule without manual SQL execution. Materialized views cannot be used. Which object fits?", options:{A:"Standard view with a scheduled task",B:"Dynamic table with a TARGET_LAG",C:"Temporary table refreshed by a stream",D:"External table with AUTO_REFRESH"}, answer:["B"], explanation:"Dynamic tables support JOINs (unlike MVs which are single-table only) and auto-refresh based on TARGET_LAG. No manual SQL needed. Standard views don't store data. External tables point to external files." },
  { id:6, domain:'D1: Architecture', multi:false, text:"An analyst runs the same SELECT query twice within 10 minutes. The underlying table had no DML between runs. The second query returns in milliseconds with zero warehouse credit usage. What served the result?", options:{A:"The SSD cache on the warehouse nodes",B:"The metadata cache in Cloud Services",C:"The result cache in the Cloud Services layer",D:"The query was optimized away by the query planner"}, answer:["C"], explanation:"Result cache serves identical query results for 24 hours (no DML changes, same role, same query text). It lives in Cloud Services and requires no warehouse. SSD cache still needs a running warehouse. Metadata cache only answers specific metadata queries like COUNT(*)." },
  { id:7, domain:'D1: Architecture', multi:false, text:"Which Snowflake tool would you use to diagnose DNS resolution and TLS certificate issues between your network and Snowflake?", options:{A:"SnowSQL",B:"SnowCD",C:"Snowflake CLI (snow)",D:"SQL API"}, answer:["B"], explanation:"SnowCD is the connectivity diagnostics tool for DNS, TLS, and OCSP checks. It does NOT execute queries. SnowSQL is a CLI for SQL. Snowflake CLI manages objects. SQL API is REST-based SQL execution." },
  { id:8, domain:'D1: Architecture', multi:true, text:"Which TWO objects are automatically created for every user without any explicit CREATE statement? (Select TWO).", options:{A:"User stage (@~)",B:"Default warehouse",C:"Table stage (@%table_name) for each table the user creates",D:"Default database",E:"Personal schema"}, answer:["A","C"], explanation:"User stages (@~) are auto-created per user. Table stages (@%table_name) are auto-created per table. Warehouses, databases, and schemas must be explicitly created or assigned." },
  { id:9, domain:'D1: Architecture', multi:false, text:"A Streamlit app deployed in Snowflake is running slowly. Where does the app's compute actually execute?", options:{A:"On the end user's browser",B:"On Snowflake-managed compute within the account",C:"On the developer's local machine",D:"On a dedicated external cloud VM"}, answer:["B"], explanation:"Streamlit in Snowflake runs on Snowflake-managed compute inside the account, not on the client's browser or local machine. The browser only renders the UI." },
  { id:10, domain:'D1: Architecture', multi:false, text:"A session parameter is set at three levels: account=10, session=20, object=30. What value does the session use?", options:{A:"10 (account level always wins)",B:"20 (session level applies to sessions)",C:"30 (most specific level wins)",D:"The average of all three values"}, answer:["C"], explanation:"Parameter hierarchy: Object > Session > Account. The most specific level wins. Object-level (30) overrides session (20) which overrides account (10)." },
  { id:11, domain:'D2: Security', multi:true, text:"An auditor asks: 'Show me every privilege the ANALYST role has, and also show me which users and roles have been granted the ANALYST role.' Which TWO commands provide this information? (Select TWO).", options:{A:"SHOW GRANTS TO ROLE ANALYST",B:"SHOW GRANTS OF ROLE ANALYST",C:"SHOW GRANTS FOR USER analyst_user",D:"SHOW GRANTS ON ROLE ANALYST",E:"SHOW GRANTS BY ROLE ANALYST"}, answer:["A","B"], explanation:"SHOW GRANTS TO ROLE = what privileges the role holds. SHOW GRANTS OF ROLE = who (users/roles) has been granted this role. FOR USER and BY ROLE are invalid syntax. ON ROLE shows grants on the role object itself, not what the role can do." },
  { id:12, domain:'D2: Security', multi:false, text:"A network policy has ALLOWED_IP_LIST = '10.0.0.0/24' and BLOCKED_IP_LIST = '10.0.0.50'. A connection comes from 10.0.0.50. What happens?", options:{A:"Connection succeeds because ALLOWED takes precedence",B:"Connection is denied because BLOCKED takes precedence over ALLOWED",C:"Connection succeeds because user-level overrides account-level",D:"An error is thrown due to conflicting rules"}, answer:["B"], explanation:"BLOCKED_IP_LIST takes precedence over ALLOWED_IP_LIST. Even though 10.0.0.50 is within the allowed range, the explicit block denies the connection. No error is thrown; it's a silent deny." },
  { id:13, domain:'D2: Security', multi:false, text:"A junior DBA creates a custom role called ETL_ROLE but does not grant it to any system role. Which problem does this cause?", options:{A:"The role cannot be used by any user",B:"ACCOUNTADMIN cannot see objects created by ETL_ROLE",C:"The role is automatically dropped after 24 hours",D:"The role inherits all privileges from PUBLIC"}, answer:["B"], explanation:"Best practice: grant custom roles to SYSADMIN so ACCOUNTADMIN (which inherits SYSADMIN) can see all objects. Without this grant, objects created by ETL_ROLE become 'orphaned' from the admin hierarchy. The role still works, but admins lose visibility." },
  { id:14, domain:'D2: Security', multi:false, text:"A resource monitor is configured to track credits on three warehouses. When does it trigger a SUSPEND action?", options:{A:"When ANY one of the three warehouses exceeds its individual credit threshold",B:"When the COMBINED credit usage across all three warehouses reaches the threshold",C:"Only when all three warehouses simultaneously exceed the threshold",D:"Resource monitors cannot track multiple warehouses"}, answer:["B"], explanation:"A resource monitor tracks the aggregate (combined) credit usage across all assigned warehouses. The threshold applies to the total, not per-warehouse. A single warehouse consuming all credits can trigger it." },
  { id:15, domain:'D2: Security', multi:false, text:"Which authentication method should a Kafka connector use to authenticate with Snowflake for streaming data ingestion?", options:{A:"Username and password",B:"SAML 2.0 SSO",C:"Key-pair authentication (RSA)",D:"Multi-factor authentication (MFA)"}, answer:["C"], explanation:"Key-pair (RSA) authentication is recommended for programmatic connectors like Kafka, JDBC drivers, and SnowSQL. SSO and MFA are for interactive/browser login. Username/password is less secure for automation." },
  { id:16, domain:'D2: Security', multi:false, text:"A tag called PII_LEVEL is attached to 200 columns across the account. No masking policy is attached to the tag. What protection does the tag provide?", options:{A:"The tagged columns are automatically masked for non-admin roles",B:"The tag provides metadata classification only, no data protection",C:"The tag blocks SELECT queries on those columns",D:"The tag encrypts the column values with a tag-specific key"}, answer:["B"], explanation:"Tags are metadata labels ONLY. They do NOT enforce any protection by themselves. You must attach a masking policy to a tag (tag-based masking) for enforcement. Without a policy, tags are just documentation." },
  { id:17, domain:'D2: Security', multi:true, text:"Which TWO views from SNOWFLAKE.ACCOUNT_USAGE would you query to find both who ran queries yesterday and what data they accessed at the column level? (Select TWO).", options:{A:"QUERY_HISTORY",B:"ACCESS_HISTORY",C:"OBJECT_DEPENDENCIES",D:"LOGIN_HISTORY",E:"WAREHOUSE_METERING_HISTORY"}, answer:["A","B"], explanation:"QUERY_HISTORY shows who ran queries (user, query text, duration). ACCESS_HISTORY tracks column-level data access (which columns were read/modified). OBJECT_DEPENDENCIES shows object-to-object references, not user access. LOGIN_HISTORY is auth events only." },
  { id:18, domain:'D3: Loading', multi:false, text:"A COPY INTO command fails with 'String too long for column VARCHAR(50)'. The team wants to load the data anyway, truncating oversized values rather than failing. Which parameter fixes this?", options:{A:"ON_ERROR = CONTINUE",B:"TRUNCATECOLUMNS = TRUE",C:"FORCE = TRUE",D:"ERROR_ON_COLUMN_COUNT_MISMATCH = FALSE"}, answer:["B"], explanation:"TRUNCATECOLUMNS = TRUE truncates strings that exceed the target column length instead of erroring. ON_ERROR = CONTINUE skips bad rows (doesn't fix them). FORCE reloads already-loaded files. ERROR_ON_COLUMN_COUNT_MISMATCH handles column count differences, not string length." },
  { id:19, domain:'D3: Loading', multi:false, text:"A bulk COPY INTO loaded files 60 days ago. Running the same COPY INTO again today skips those files. Running it 70 days later, the same files load again as new. Why?", options:{A:"Snowflake purged the files from the stage after 60 days",B:"Bulk COPY metadata expires after 64 days, so files appear new",C:"The warehouse cache was cleared after 60 days",D:"The FORCE parameter was automatically enabled after timeout"}, answer:["B"], explanation:"Bulk COPY INTO metadata (which tracks loaded files for deduplication) expires after 64 days. After that, files are treated as new and loaded again. Snowpipe metadata lasts 14 days. This is not related to stage cleanup or cache." },
  { id:20, domain:'D3: Loading', multi:false, text:"A Snowpipe job encounters corrupt rows in a file. What is the DEFAULT behavior?", options:{A:"The entire load job aborts",B:"The entire file is skipped",C:"Only the corrupt rows are skipped, valid rows are loaded",D:"The file is moved to a quarantine stage"}, answer:["B"], explanation:"Snowpipe default ON_ERROR = SKIP_FILE. The entire file with errors is skipped. Bulk COPY default is ABORT_STATEMENT. CONTINUE would skip only bad rows. There is no automatic quarantine stage." },
  { id:21, domain:'D3: Loading', multi:false, text:"You need to load a JSON file where each element is nested inside an outer array [ ]. Without any special option, Snowflake loads the entire array as one row. Which file format option fixes this?", options:{A:"STRIP_NULL_VALUES = TRUE",B:"STRIP_OUTER_ARRAY = TRUE",C:"MATCH_BY_COLUMN_NAME = CASE_INSENSITIVE",D:"PARSE_HEADER = TRUE"}, answer:["B"], explanation:"STRIP_OUTER_ARRAY = TRUE removes the outer [ ] from JSON, loading each array element as a separate row. STRIP_NULL_VALUES converts JSON null to SQL NULL. MATCH_BY_COLUMN_NAME and PARSE_HEADER are for CSV-like matching." },
  { id:22, domain:'D3: Loading', multi:true, text:"Which TWO COPY INTO parameters would you combine to load files matching a naming pattern AND automatically delete them from the stage after successful loading? (Select TWO).", options:{A:"PATTERN = '.*sales.*[.]csv'",B:"FILES = ('sales_jan.csv', 'sales_feb.csv')",C:"PURGE = TRUE",D:"FORCE = TRUE",E:"VALIDATION_MODE = 'RETURN_ALL_ERRORS'"}, answer:["A","C"], explanation:"PATTERN filters files by regex. PURGE = TRUE deletes successfully loaded files from the stage. FILES specifies exact names (not a pattern). FORCE reloads already-loaded files. VALIDATION_MODE is dry-run only (no loading)." },
  { id:23, domain:'D3: Loading', multi:false, text:"A data engineer needs to track the source filename for each row loaded into a table. Which approach works during COPY INTO with a SELECT transform?", options:{A:"Use CURRENT_FILENAME() system function",B:"Use the METADATA$FILENAME pseudo-column in the SELECT",C:"Enable FILE_TRACKING = TRUE on the stage",D:"Query COPY_HISTORY after loading to join filenames"}, answer:["B"], explanation:"METADATA$FILENAME is a pseudo-column available during COPY INTO with SELECT transforms. It returns the source filename for each row. CURRENT_FILENAME() and FILE_TRACKING do not exist. COPY_HISTORY shows file-level info, not row-level." },
  { id:24, domain:'D3: Loading', multi:false, text:"A stream on TABLE_A has not been consumed for 30 days. The table has DATA_RETENTION_TIME_IN_DAYS=1 and MAX_DATA_EXTENSION_TIME_IN_DAYS=14. What is the stream's status?", options:{A:"Active, because 30 days is within the default extension",B:"Stale, because 30 days exceeds the greater of retention (1) and extension (14)",C:"Active, because streams never go stale on permanent tables",D:"Stale, because 30 days exceeds DATA_RETENTION_TIME_IN_DAYS (1 day)"}, answer:["B"], explanation:"Stream staleness threshold = GREATER of (DATA_RETENTION_TIME, MAX_DATA_EXTENSION_TIME) = MAX(1, 14) = 14 days. 30 days > 14 days, so the stream is stale. Must DROP and RECREATE. Cannot be refreshed with ALTER." },
  { id:25, domain:'D3: Loading', multi:false, text:"A task DAG has a root task and three child tasks. The developer tries to add a SCHEDULE clause to one of the child tasks. What happens?", options:{A:"The child task runs on its own schedule independently",B:"The command fails because only the root task can have a SCHEDULE",C:"The child task's schedule overrides the root task's schedule",D:"Both schedules run, creating parallel execution paths"}, answer:["B"], explanation:"In a task DAG, only the root task has a SCHEDULE. Child tasks are triggered by their predecessors completing. Adding a SCHEDULE to a child task is not allowed." },
  { id:26, domain:'D3: Loading', multi:true, text:"Which TWO statements about Snowpipe Streaming (via the Ingest SDK) are true? (Select TWO).", options:{A:"Rows are inserted directly without staging files first",B:"It uses the same cloud event notifications as regular Snowpipe",C:"It provides lower latency than file-based Snowpipe",D:"It requires a user-managed warehouse for processing",E:"Rows are immediately written as micro-partitions"}, answer:["A","C"], explanation:"Snowpipe Streaming inserts rows directly (no file staging) with lower latency than file-based Snowpipe. Rows go to internal buffers first, then asynchronously migrated to micro-partitions (not immediately). It does not use cloud events and is serverless." },
  { id:27, domain:'D4: Performance', multi:true, text:"Which TWO functions return approximate cardinality estimates using the HyperLogLog algorithm? (Select TWO).", options:{A:"HLL()",B:"APPROX_COUNT_DISTINCT()",C:"COUNT(DISTINCT col)",D:"HASH_AGG()",E:"CHECKSUM_AGG()"}, answer:["A","B"], explanation:"HLL() is an alias for APPROX_COUNT_DISTINCT(). Both use the HyperLogLog algorithm for fast approximate cardinality estimation with a small error margin. COUNT(DISTINCT) is exact. HASH_AGG() and CHECKSUM_AGG() compute hash-based aggregates, not cardinality estimates." },
  { id:28, domain:'D4: Performance', multi:false, text:"A table has a clustering key on (region, order_date). A query filters WHERE order_date = '2026-01-15' but does NOT filter on region. How effective is partition pruning?", options:{A:"Highly effective because order_date is in the clustering key",B:"Partially effective, but less optimal than if region were also filtered",C:"Not effective at all because the first clustering column is not filtered",D:"Pruning only works if all clustering columns are in the WHERE clause"}, answer:["B"], explanation:"Pruning is partially effective because order_date metadata exists in micro-partitions, but since region (the first/lower-cardinality column) is not filtered, the pruning is less precise than filtering on both columns. It's not completely ineffective." },
  { id:29, domain:'D4: Performance', multi:false, text:"A warehouse processes a single complex analytical query that spills heavily to remote storage but there is NO queuing. What is the best fix?", options:{A:"Enable multi-cluster with STANDARD scaling",B:"Scale UP to a larger warehouse size",C:"Enable Query Acceleration Service",D:"Add a clustering key to the queried table"}, answer:["B"], explanation:"Single complex query + spilling + no queuing = needs more memory/compute per node = scale UP. Multi-cluster addresses concurrency/queuing, not single-query memory. QAS helps outlier queries but scaling up directly addresses spilling." },
  { id:30, domain:'D4: Performance', multi:false, text:"SYSTEM$CLUSTERING_INFORMATION returns an average_depth of 15 for a table. What does this indicate?", options:{A:"The table is well-clustered (depth near 1 is ideal)",B:"The table is poorly clustered and would benefit from reclustering",C:"The table has 15 micro-partitions",D:"The clustering key has 15 columns"}, answer:["B"], explanation:"Clustering depth near 1.0 is ideal (well-clustered). A depth of 15 means significant overlap between micro-partitions, causing poor pruning. The table would benefit from adding or adjusting a clustering key. Depth is not the partition count or column count." },
  { id:31, domain:'D4: Performance', multi:false, text:"A dashboard query runs repeatedly every 5 minutes by 200 concurrent BI users. The underlying data changes hourly via ETL. Which optimization MOST reduces warehouse cost?", options:{A:"Create a materialized view on the query",B:"Increase the warehouse size to handle 200 users",C:"Rely on the result cache since the query is identical and data hasn't changed",D:"Create a clustering key on the dashboard filter columns"}, answer:["C"], explanation:"Result cache serves identical queries for up to 24 hours with zero warehouse credits when data hasn't changed. With hourly ETL, the cache is valid between refreshes. 200 users running the same query = massive cost savings from cache. MV adds serverless cost. Scaling up costs more." },
  { id:32, domain:'D4: Performance', multi:false, text:"A table stores a UUID column (billions of unique values). Point lookups on UUID are slow despite a clustering key on another column. Which optimization targets this specific problem?", options:{A:"Add UUID as the first column in the clustering key",B:"Enable Search Optimization Service on the UUID column",C:"Enable Query Acceleration Service",D:"Create a materialized view filtered on UUID"}, answer:["B"], explanation:"Search Optimization Service (SOS) creates search access paths optimized for equality/IN lookups on HIGH cardinality columns like UUIDs. Clustering is for low-medium cardinality range filters. QAS handles outlier queries. MVs don't optimize point lookups." },
  { id:33, domain:'D4: Performance', multi:true, text:"Which TWO statements about the FLATTEN function are correct? (Select TWO).", options:{A:"FLATTEN converts a VARIANT array into rows (one row per element)",B:"FLATTEN can only be used on ARRAY types, not OBJECT types",C:"FLATTEN is used with LATERAL in the FROM clause",D:"FLATTEN modifies the original table data in place",E:"FLATTEN requires Enterprise Edition or higher"}, answer:["A","C"], explanation:"FLATTEN explodes arrays/objects into rows and is used with LATERAL JOIN in the FROM clause. It works on both ARRAY and OBJECT types. It does not modify data (it's a table function). Available on all editions." },
  { id:34, domain:'D4: Performance', multi:false, text:"An analyst runs SELECT * FROM large_table WHERE region IN ('US', 'EU', 'APAC'). The table has no clustering key. Query Profile shows 95% of partitions scanned. The region column has 5 distinct values. Best optimization?", options:{A:"Enable Search Optimization Service on the region column",B:"Add a clustering key with region as the first column",C:"Scale up the warehouse to XL",D:"Rewrite the query to use UNION ALL instead of IN"}, answer:["B"], explanation:"Region has 5 distinct values (very low cardinality) and is used in WHERE filters = ideal clustering key candidate. SOS is for high cardinality equality lookups. Scaling up doesn't reduce partitions scanned. UNION ALL doesn't improve pruning." },
  { id:35, domain:'D4: Performance', multi:false, text:"Which Snowflake function converts semi-structured JSON keys and values from a single row into a relational column format (key, value, path)?", options:{A:"PARSE_JSON()",B:"OBJECT_CONSTRUCT()",C:"FLATTEN()",D:"TRY_PARSE_JSON()"}, answer:["C"], explanation:"FLATTEN with RECURSIVE => TRUE on an OBJECT produces rows with KEY, VALUE, PATH columns from nested JSON. PARSE_JSON converts a string to VARIANT. OBJECT_CONSTRUCT builds JSON from relational columns (the reverse). TRY_PARSE_JSON is a safe parse variant." },
  { id:36, domain:'D5: Sharing', multi:false, text:"A consumer creates a database from a share and attempts to run INSERT INTO on a shared table. What happens?", options:{A:"The INSERT succeeds and data is stored in the consumer's account",B:"The INSERT fails because shared objects are read-only",C:"The INSERT succeeds but changes are visible only to the consumer",D:"The INSERT is queued until the provider approves it"}, answer:["B"], explanation:"Shared data is READ-ONLY. Consumers cannot INSERT, UPDATE, DELETE, MERGE, or CLONE shared objects. To get a writable copy, the consumer must CREATE TABLE AS SELECT from the shared object." },
  { id:37, domain:'D5: Sharing', multi:false, text:"A provider shares data with a consumer via a direct share. The provider then drops a table included in the share. What does the consumer experience?", options:{A:"The table remains available from a cached copy",B:"The consumer's entire shared database is dropped automatically",C:"The table becomes immediately inaccessible to the consumer",D:"The consumer gets a notification but can still query for 24 hours"}, answer:["C"], explanation:"When a provider drops a shared table, it becomes immediately inaccessible to consumers. There is no cached copy, grace period, or notification. The consumer's database shell remains but the object is gone." },
  { id:38, domain:'D5: Sharing', multi:true, text:"Which TWO capabilities does a Reader Account have that might surprise someone given its name? (Select TWO).", options:{A:"Create and manage virtual warehouses",B:"Create shares to share data with other accounts",C:"Create databases, schemas, and tables",D:"Access the Snowflake Marketplace",E:"Create storage integrations for external stages"}, answer:["A","C"], explanation:"Despite the name 'Reader', these accounts CAN create warehouses, databases, schemas, tables, views, users, and roles. They CANNOT create shares, access Marketplace, or create pipes/stages. The provider pays for all compute." },
  { id:39, domain:'D5: Sharing', multi:false, text:"A company needs to share data with a partner in a DIFFERENT cloud region. Direct shares do not work cross-region. What Snowflake feature enables this?", options:{A:"Replication groups with manual refresh",B:"Listings with Auto-Fulfillment",C:"Database cloning across accounts",D:"External tables pointing to the partner's bucket"}, answer:["B"], explanation:"Direct shares are same-region only. Listings with Auto-Fulfillment replicate data cross-region (and cross-cloud) automatically. Replication groups are for DR/failover. Cloning is within an account. External tables point to files, not cross-account sharing." },
  { id:40, domain:'D5: Sharing', multi:false, text:"A permanent table has DATA_RETENTION_TIME_IN_DAYS = 10 and the default 7-day fail-safe. What is the total data protection window?", options:{A:"10 days",B:"7 days",C:"17 days",D:"3 days"}, answer:["C"], explanation:"Total data protection = Time Travel + Fail-safe. 10 days (Time Travel) + 7 days (Fail-safe) = 17 days. Time Travel is user-accessible (UNDROP, AT/BEFORE). Fail-safe is Snowflake Support only." },
];

const QUESTIONS_E05 = [
  { id:1, domain:'D1: Architecture', multi:false, text:"A data engineer needs to calculate the hourly credit cost of running a LARGE warehouse continuously for 3 hours. Given that each size increase doubles the credits, and an X-Small warehouse costs 1 credit/hour, how many total credits will the LARGE warehouse consume?", options:{A:"24 credits",B:"16 credits",C:"12 credits",D:"32 credits"}, answer:["A"], explanation:"X-Small=1, Small=2, Medium=4, Large=8 credits/hour. 8 credits/hour x 3 hours = 24 credits total." },
  { id:2, domain:'D1: Architecture', multi:false, text:"A warehouse is started, runs one query for 45 seconds, and is then suspended. How many seconds of compute are billed?", options:{A:"120 seconds",B:"60 seconds",C:"45 seconds",D:"0 seconds — the warehouse was suspended before 1 minute"}, answer:["B"], explanation:"Snowflake bills per-second with a 60-second minimum each time a warehouse starts. Since 45 seconds < 60 seconds, the minimum of 60 seconds applies." },
  { id:3, domain:'D1: Architecture', multi:false, text:"Which Snowflake table type persists only for the duration of the user session and is automatically dropped when the session ends?", options:{A:"Transient table",B:"External table",C:"Permanent table",D:"Temporary table"}, answer:["D"], explanation:"Temporary tables exist only within the session that created them and are automatically dropped when the session ends. Transient tables persist across sessions but have no Fail-safe. Permanent tables have full data protection." },
  { id:4, domain:'D1: Architecture', multi:false, text:"Which Snowflake edition is the MINIMUM required to enable multi-cluster warehouses?", options:{A:"Multi-cluster warehouses are available in all editions",B:"Standard",C:"Enterprise",D:"Virtual Private Snowflake"}, answer:["C"], explanation:"Multi-cluster warehouses are an Enterprise Edition feature. Standard Edition only supports single-cluster warehouses." },
  { id:5, domain:'D1: Architecture', multi:false, text:"A Dynamic Table is defined with TARGET_LAG = '5 minutes' and references a base table. Which statement best describes how it stays current?", options:{A:"An automated refresh process incrementally updates it to stay within the specified lag",B:"It uses a stream behind the scenes to capture changes and a task to apply them",C:"It re-executes the full query every 5 minutes regardless of changes",D:"It relies on the result cache to serve stale data until 5 minutes elapse"}, answer:["A"], explanation:"Dynamic tables use an automated refresh process that determines the schedule to keep data within the target lag. It uses incremental processing when possible, only processing changed data rather than recomputing the entire table." },
  { id:6, domain:'D1: Architecture', multi:false, text:"A Materialized View is created on a single base table. A user queries the base table directly. How does Snowflake handle this?", options:{A:"Snowflake always forces the query to read from the MV instead",B:"The query fails because the MV must be queried directly",C:"The query optimizer may automatically rewrite the query to use the MV if beneficial",D:"The MV is only used if explicitly referenced in the FROM clause"}, answer:["C"], explanation:"Unlike dynamic tables, the query optimizer can automatically rewrite queries against the base table to use a materialized view when it determines the MV can satisfy the query more efficiently. This is transparent to the user." },
  { id:7, domain:'D1: Architecture', multi:false, text:"Cloud services usage is billed to your account. Under what condition is cloud services consumption waived?", options:{A:"When total monthly cloud services credits are under 100",B:"Cloud services are always free",C:"When the account is on Enterprise Edition or higher",D:"When daily cloud services usage is less than 10% of daily warehouse usage"}, answer:["D"], explanation:"Cloud services are charged only when daily consumption exceeds 10% of the daily virtual warehouse credit usage. If cloud services stay under 10%, they are adjusted (waived) on that day's billing." },
  { id:8, domain:'D1: Architecture', multi:false, text:"A team wants to build a multi-table transformation pipeline declaratively, where each stage materializes results and automatically refreshes. Which Snowflake object is best suited for this?", options:{A:"Dynamic tables chained together",B:"A series of secure views",C:"Materialized views chained together",D:"External tables with auto-refresh"}, answer:["A"], explanation:"Dynamic tables support complex queries including joins and can be chained into multi-level pipelines. Materialized views only support a single base table and cannot be based on complex queries with joins." },
  { id:9, domain:'D1: Architecture', multi:false, text:"What is a key difference between a Dynamic Table and a Materialized View?", options:{A:"Dynamic tables cannot use joins; materialized views can",B:"Materialized views are always fresher than dynamic tables",C:"Dynamic tables support complex queries with joins; materialized views support only a single base table",D:"Materialized views require manual scheduling; dynamic tables do not"}, answer:["C"], explanation:"Dynamic tables can be based on complex queries with joins and unions. Materialized views are limited to a single base table without joins. However, MV data is always current, while DT data freshness depends on target lag." },
  { id:10, domain:'D2: Security', multi:false, text:"What is the purpose of the USERADMIN system role in Snowflake?", options:{A:"Creating and managing warehouses and databases",B:"Managing account-level settings like billing and resource monitors",C:"Creating users and roles, and granting roles to users",D:"Granting privileges on all objects and managing the role hierarchy"}, answer:["C"], explanation:"USERADMIN is designed for creating and managing users and roles. SYSADMIN creates warehouses/databases. ACCOUNTADMIN handles account-level settings. SECURITYADMIN manages the full role hierarchy and grants." },
  { id:11, domain:'D2: Security', multi:false, text:"A managed access schema has been created. Who can grant privileges on objects within that schema?", options:{A:"Only the schema owner or a role with MANAGE GRANTS",B:"Any role with OWNERSHIP on the individual objects",C:"Only ACCOUNTADMIN",D:"Any role with the USAGE privilege on the schema"}, answer:["A"], explanation:"In a managed access schema, only the schema owner (the role with OWNERSHIP on the schema) or a role with MANAGE GRANTS can grant or revoke privileges on objects. Individual object owners cannot grant privileges themselves." },
  { id:12, domain:'D2: Security', multi:false, text:"A resource monitor is set with SUSPEND at 80% and SUSPEND_IMMEDIATE at 100%. The combined usage of its assigned warehouses reaches 80%. What happens to currently running queries?", options:{A:"All running queries are immediately terminated",B:"The warehouse is dropped from the account",C:"Running queries complete, but no new queries can start on the warehouses",D:"Nothing happens until 100% is reached"}, answer:["C"], explanation:"SUSPEND at 80% allows running queries to finish but prevents new queries. SUSPEND_IMMEDIATE at 100% kills running queries immediately. The two thresholds serve different purposes — graceful vs. hard stop." },
  { id:13, domain:'D2: Security', multi:false, text:"A security admin uses SHOW GRANTS OF ROLE ANALYST. What information is returned?", options:{A:"All roles and users that the ANALYST role has been granted TO (the role hierarchy above)",B:"All privileges granted TO the ANALYST role",C:"All objects owned by the ANALYST role",D:"All users who currently have ANALYST as their active role"}, answer:["A"], explanation:"OF ROLE shows which roles and users the specified role has been granted to. TO ROLE shows privileges granted to the role. ON ROLE shows who has been granted the role itself. These three variants serve different purposes." },
  { id:14, domain:'D2: Security', multi:false, text:"A masking policy is applied to a column on the base table. A view is created on that table without its own masking policy. When a user queries the view, does the base table's masking policy apply?", options:{A:"No — views are independent and bypass base table policies",B:"Yes — the masking policy on the base table column is inherited by the view",C:"Only if the view is a secure view",D:"Only if the user has OWNERSHIP on the base table"}, answer:["B"], explanation:"Masking policies on base table columns apply when data is accessed through views. The policy follows the column, not the object queried. This ensures data protection regardless of access path." },
  { id:15, domain:'D2: Security', multi:false, text:"A Snowflake account has a resource monitor at the account level with a credit quota of 1000. A second resource monitor with a quota of 200 is assigned to warehouse WH_REPORTS. WH_REPORTS consumes 200 credits. What is the effective limit that triggers the action?", options:{A:"1000 credits — the account-level monitor takes precedence",B:"1200 credits — the quotas are additive",C:"200 credits — the warehouse-level monitor triggers first since its quota is reached",D:"500 credits — the average of both monitors"}, answer:["C"], explanation:"When both account-level and warehouse-level resource monitors exist, the more restrictive one triggers first. The warehouse-level monitor at 200 credits is reached before the account-level monitor at 1000, so it triggers." },
  { id:16, domain:'D2: Security', multi:false, text:"Which system role inherits all other system-defined roles by default in the Snowflake role hierarchy?", options:{A:"SECURITYADMIN",B:"SYSADMIN",C:"ORGADMIN",D:"ACCOUNTADMIN"}, answer:["D"], explanation:"ACCOUNTADMIN is the top-level role in the default hierarchy. It inherits SYSADMIN and SECURITYADMIN (which itself inherits USERADMIN). ORGADMIN is a separate role for organization-level management." },
  { id:17, domain:'D3: Loading', multi:false, text:"What is the default value of the ON_ERROR parameter when using bulk COPY INTO <table> to load data?", options:{A:"CONTINUE",B:"SKIP_FILE",C:"ABORT_STATEMENT",D:"SKIP_FILE_10"}, answer:["C"], explanation:"The default ON_ERROR for bulk COPY INTO is ABORT_STATEMENT — the entire load aborts on the first error. For Snowpipe, the default is SKIP_FILE. This is a common exam trap: different defaults for bulk vs. continuous loading." },
  { id:18, domain:'D3: Loading', multi:false, text:"A COPY INTO command encounters a CSV row where a string value exceeds the target column's VARCHAR(50) length. The load fails. The engineer wants to silently cut the string to 50 characters. Which option should be set?", options:{A:"ON_ERROR = 'CONTINUE'",B:"ERROR_ON_COLUMN_COUNT_MISMATCH = FALSE",C:"FORCE = TRUE",D:"TRUNCATECOLUMNS = TRUE"}, answer:["D"], explanation:"TRUNCATECOLUMNS = TRUE silently truncates strings that exceed the target column length. ON_ERROR = CONTINUE skips the entire row on error. ERROR_ON_COLUMN_COUNT_MISMATCH handles mismatched column counts, not lengths." },
  { id:19, domain:'D3: Loading', multi:false, text:"When a Snowpipe with AUTO_INGEST=TRUE encounters an error loading a file, what is its default ON_ERROR behavior?", options:{A:"ABORT_STATEMENT",B:"SKIP_FILE",C:"CONTINUE",D:"SKIP_FILE_10"}, answer:["B"], explanation:"Snowpipe's default ON_ERROR is SKIP_FILE, which skips the entire file on error. This differs from bulk COPY INTO, which defaults to ABORT_STATEMENT. This difference is because Snowpipe operates autonomously without user intervention." },
  { id:20, domain:'D3: Loading', multi:false, text:"Which command uploads files from a local filesystem to a Snowflake internal stage?", options:{A:"COPY FILES INTO @stage FROM file://path",B:"UPLOAD file://path TO @stage",C:"PUT file://path @stage",D:"INSERT FILES INTO @stage FROM file://path"}, answer:["C"], explanation:"PUT uploads files from a local filesystem to an internal stage. GET does the reverse — downloads from stage to local. Both use the file:// prefix for local paths." },
  { id:21, domain:'D3: Loading', multi:false, text:"A user wants to stage files that will be loaded into multiple tables by multiple users. Which stage type is most appropriate?", options:{A:"Named internal stage (@my_stage)",B:"User stage (@~)",C:"Table stage (@%tablename)",D:"Temporary stage"}, answer:["A"], explanation:"Named internal stages are database objects with grantable privileges, supporting multi-user access and loading into multiple tables. User stages are single-user. Table stages are tied to one table and have no grantable privileges." },
  { id:22, domain:'D3: Loading', multi:false, text:"A table stage is referenced as @%my_table. Which of the following is a limitation of table stages?", options:{A:"They cannot be used with COPY INTO",B:"They support data transformations during loading (query as source)",C:"They have no grantable privileges — only the table owner can access them",D:"They can only hold a single file at a time"}, answer:["C"], explanation:"Table stages are implicit stages tied to the table — they are not separate database objects. They have no grantable privileges; only the table owner (OWNERSHIP privilege) can stage, list, query, or drop files. They also do not support transformations during loading." },
  { id:23, domain:'D3: Loading', multi:false, text:"You have a set of Parquet files on an external stage. You want Snowflake to automatically detect the column names and types from the files to create a table. Which function do you use?", options:{A:"INFER_SCHEMA()",B:"DESCRIBE STAGE",C:"PARSE_JSON()",D:"SHOW COLUMNS IN STAGE"}, answer:["A"], explanation:"INFER_SCHEMA detects column definitions (names, types, ordering) from staged semi-structured files including Parquet, Avro, ORC, JSON, and CSV. It can be used with CREATE TABLE ... USING TEMPLATE for automatic table creation." },
  { id:24, domain:'D3: Loading', multi:false, text:"When creating a named external stage, you must specify a URL pointing to cloud storage. If the storage is private, what is the RECOMMENDED way to provide authentication credentials?", options:{A:"Use a network policy to allow the stage to access cloud storage",B:"Embed AWS_KEY_ID and AWS_SECRET_KEY directly in the CREDENTIALS parameter",C:"Store credentials in a Snowflake secret and reference it in the stage definition",D:"Use a storage integration object to delegate authentication"}, answer:["D"], explanation:"Snowflake highly recommends storage integrations for external stages. They delegate authentication to a Snowflake IAM entity, avoiding hard-coded credentials. Direct credentials (AWS_KEY_ID) work but are not recommended." },
  { id:25, domain:'D3: Loading', multi:false, text:"A task is configured with WHEN SYSTEM$STREAM_HAS_DATA('my_stream'). The task's schedule fires every 5 minutes. If the stream has no new data, what happens?", options:{A:"The task runs but processes zero rows",B:"The task is skipped entirely and does not consume warehouse credits",C:"The task fails with an empty stream error",D:"The task still runs and is billed for the minimum 60 seconds"}, answer:["B"], explanation:"The WHEN condition is evaluated before the task runs. If SYSTEM$STREAM_HAS_DATA returns FALSE, the task is skipped entirely — no warehouse is started and no credits are consumed." },
  { id:26, domain:'D4: Performance', multi:false, text:"SYSTEM$CLUSTERING_INFORMATION for a table returns an average_depth of 1.2 on the clustering key columns. What does this indicate?", options:{A:"The table is well-clustered with minimal micro-partition overlap",B:"The table is very poorly clustered and needs immediate reclustering",C:"The clustering key was recently dropped",D:"The table has only 1.2 micro-partitions total"}, answer:["A"], explanation:"Average clustering depth measures how many micro-partitions overlap for the key columns. A value close to 1 means excellent clustering — each partition has minimal overlap with others, enabling very effective pruning." },
  { id:27, domain:'D4: Performance', multi:false, text:"Which Snowflake feature is designed to accelerate point-lookup queries (equality predicates) and substring searches on large tables, without reorganizing micro-partitions?", options:{A:"Automatic Clustering",B:"Materialized Views",C:"Query Acceleration Service (QAS)",D:"Search Optimization Service (SOS)"}, answer:["D"], explanation:"Search Optimization Service creates auxiliary data structures to speed up selective point lookups (equality, IN, LIKE, substring, geo). Unlike clustering, it does not reorganize data. QAS accelerates scatter-heavy queries by offloading work, not point lookups." },
  { id:28, domain:'D4: Performance', multi:false, text:"A user runs an identical SELECT query three times. The first execution takes 8 seconds. The second returns instantly from the result cache. Before the third execution, an INSERT adds one row to the table. How long does the third query take?", options:{A:"Instant — the result cache is not affected by single-row inserts",B:"About 8 seconds — the result cache is invalidated because the underlying data changed",C:"About 4 seconds — only the new row is processed",D:"It depends on whether the warehouse was suspended between queries"}, answer:["B"], explanation:"Any DML operation on the underlying table invalidates the result cache for queries against that table. Even a single INSERT forces re-execution. The third query runs against the warehouse again, taking approximately the same time." },
  { id:29, domain:'D4: Performance', multi:false, text:"During peak business hours, users report that queries are taking longer than usual. The Query Profile shows significant time in the 'Queued' state. The warehouse is a single-cluster LARGE. What is the BEST remediation?", options:{A:"Scale up to X-Large to process individual queries faster",B:"Enable multi-cluster auto-scaling (scale out) to handle concurrent query load",C:"Add a clustering key to the most queried table",D:"Increase the statement timeout parameter"}, answer:["B"], explanation:"Queuing during peak hours indicates concurrency contention — too many queries for one cluster. Scale out (multi-cluster) adds clusters to handle concurrent users. Scale up makes individual queries faster but doesn't help concurrency." },
  { id:30, domain:'D4: Performance', multi:false, text:"The function HLL() in Snowflake is an alias for which function?", options:{A:"HASH_AGG()",B:"COUNT(DISTINCT)",C:"APPROX_PERCENTILE()",D:"APPROX_COUNT_DISTINCT()"}, answer:["D"], explanation:"HLL() is an alias for APPROX_COUNT_DISTINCT(). Both use the HyperLogLog algorithm for approximate cardinality estimation. COUNT(DISTINCT) is the exact (not approximate) equivalent." },
  { id:31, domain:'D4: Performance', multi:false, text:"A query's Query Profile shows 'Bytes Spilled to Remote Storage: 15 GB'. What does this indicate and what is the recommended action?", options:{A:"Intermediate data exceeded both memory and local SSD; scale up to a larger warehouse",B:"Remote storage latency slowed the query; switch to an internal stage",C:"The warehouse is overloaded with concurrent queries; scale out instead",D:"The query result set was too large for the client; paginate the results"}, answer:["A"], explanation:"Spilling to remote storage means intermediate data exceeded both warehouse memory AND the local SSD cache, overflowing to cloud storage (S3/Blob/GCS). This is more severe than local spilling. A larger warehouse provides more memory and SSD to prevent both levels of spilling." },
  { id:32, domain:'D4: Performance', multi:false, text:"You need to convert rows into columns — for example, transforming monthly revenue rows into columns like JAN, FEB, MAR. Which SQL clause achieves this natively in Snowflake?", options:{A:"UNPIVOT",B:"PIVOT",C:"TRANSPOSE",D:"CROSSTAB"}, answer:["B"], explanation:"PIVOT rotates rows into columns, aggregating values. UNPIVOT does the reverse — columns into rows. TRANSPOSE and CROSSTAB are not Snowflake SQL clauses." },
  { id:33, domain:'D4: Performance', multi:false, text:"A VARIANT column named DATA contains: {'items': [{'name': 'Laptop'}, {'name': 'Mouse'}]}. You need to extract each item name as a separate row. Which approach is correct?", options:{A:"SELECT DATA:items:name FROM table",B:"SELECT f.value:name::STRING FROM table, LATERAL FLATTEN(input => DATA:items) f",C:"SELECT ARRAY_SLICE(DATA:items, 0, 2) FROM table",D:"SELECT PARSE_JSON(DATA):items FROM table"}, answer:["B"], explanation:"LATERAL FLATTEN expands an array into individual rows. Each row's value field contains one array element, which can then be traversed with colon notation. Option A would not produce separate rows." },
  { id:34, domain:'D4: Performance', multi:false, text:"Which SQL clause is unique to Snowflake and allows filtering the results of a window function directly, without requiring a subquery or CTE?", options:{A:"HAVING",B:"WITHIN GROUP",C:"QUALIFY",D:"PARTITION BY"}, answer:["C"], explanation:"QUALIFY filters results of window functions (like ROW_NUMBER, RANK) directly in the query, similar to how HAVING filters aggregate results. Without QUALIFY, you would need a subquery or CTE to filter on window function output." },
  { id:35, domain:'D4: Performance', multi:false, text:"A Snowflake VARIANT column stores data using bracket notation: DATA['address']['city']. Which alternative notation also works to access the same nested value?", options:{A:"DATA.address.city",B:"GET(DATA, 'address.city')",C:"JSON_EXTRACT(DATA, '$.address.city')",D:"DATA:address.city"}, answer:["D"], explanation:"Snowflake supports colon notation (DATA:address.city or DATA:address:city) and bracket notation (DATA['address']['city']). All-dot notation (DATA.address.city) does NOT work — the first accessor must use colon or bracket." },
  { id:36, domain:'D5: Sharing', multi:false, text:"A transient table has DATA_RETENTION_TIME_IN_DAYS = 1. How many total days of data protection does this table have (Time Travel + Fail-safe combined)?", options:{A:"8 days (1 TT + 7 FS)",B:"7 days (Fail-safe only)",C:"1 day (1 TT + 0 FS)",D:"0 days (transient tables have no protection)"}, answer:["C"], explanation:"Transient tables have NO Fail-safe period. Total protection = Time Travel only. With retention=1, the total is 1 day. Only permanent tables get the additional 7-day Fail-safe. Total = TT + FS, and FS=0 for transient." },
  { id:37, domain:'D5: Sharing', multi:false, text:"A data provider shares a table via a Direct Share with a consumer account. Which of the following can the CONSUMER do with the shared data?", options:{A:"Clone the shared table into their own database",B:"Create a view on top of the shared database to query it",C:"Modify the shared table by inserting rows",D:"Re-share the data with a third-party account"}, answer:["B"], explanation:"Consumers can create a database from the share and query it (including creating views on shared objects). They CANNOT clone shared objects, modify shared data, or re-share it to another account." },
  { id:38, domain:'D5: Sharing', multi:false, text:"An Enterprise account has a permanent table with total data protection of 37 days. Given that Fail-safe is always 7 days for permanent tables, what is the DATA_RETENTION_TIME_IN_DAYS setting on this table?", options:{A:"37 days",B:"44 days",C:"7 days",D:"30 days"}, answer:["D"], explanation:"Total protection = TT + FS. For permanent tables, FS = 7. 37 total - 7 FS = 30 days Time Travel. So DATA_RETENTION_TIME_IN_DAYS = 30. Enterprise edition supports up to 90 days of TT." },
  { id:39, domain:'D5: Sharing', multi:false, text:"What happens when a provider creates a reader account for a non-Snowflake consumer? Who pays for the compute resources the consumer uses?", options:{A:"The provider pays — reader account compute charges appear on the provider's bill",B:"The consumer pays — they are billed directly by Snowflake",C:"Snowflake absorbs the cost as part of the Marketplace fee",D:"Neither — reader accounts cannot execute queries"}, answer:["A"], explanation:"Reader accounts (managed accounts) are created and paid for by the provider. All compute costs for warehouses and queries in the reader account appear on the provider's bill. The consumer has no direct Snowflake billing relationship." },
  { id:40, domain:'D5: Sharing', multi:false, text:"A Direct Share allows a provider in us-east-1 to share data with a consumer. In which scenario does the consumer receive the shared data without replication?", options:{A:"The consumer is in any AWS region",B:"The consumer is in the same cloud region (us-east-1) as the provider",C:"The consumer is on a different cloud provider (Azure or GCP)",D:"Direct Shares always require replication regardless of region"}, answer:["B"], explanation:"Direct Shares work within the same cloud provider AND region without replication. Cross-region or cross-cloud sharing requires replication or auto-fulfillment through listings. Same-region sharing uses zero-copy — the consumer reads directly from the provider's storage." },
];

const QUESTIONS_E06 = [
  {"id":1,"domain":"D1: Architecture","multi":false,"text":"A data engineering team uses a stream to feed an ELT pipeline that merges changes into a target table. The source table receives INSERT, UPDATE, and DELETE operations. The pipeline must capture all three operation types to correctly apply merges. Which stream configuration is appropriate?","options":{"A":"An append-only stream, since it captures the net result of all changes","B":"A standard stream with default settings","C":"An insert-only stream configured on the source table","D":"A standard stream with SHOW_INITIAL_ROWS = TRUE to include pre-existing data"},"answer":["B"],"explanation":"Standard streams capture INSERT, UPDATE, and DELETE operations via METADATA$ACTION and METADATA$ISUPDATE columns. Append-only streams only track inserts (ignoring deletes/updates). Insert-only streams are exclusively for external tables. SHOW_INITIAL_ROWS controls whether existing rows appear at stream creation — it does not affect which DML types are captured."},
  {"id":2,"domain":"D1: Architecture","multi":false,"text":"A developer clones a production database containing 500 tables. Immediately after the CLONE command completes, which statement about the cloned database is TRUE?","options":{"A":"Storage costs double because each table's micro-partitions are physically copied","B":"The clone contains references to the same micro-partitions and additional storage is consumed only as data diverges","C":"Internal stages within the database are also cloned with their file contents","D":"External tables in the source database appear in the clone with full data access"},"answer":["B"],"explanation":"Snowflake cloning is zero-copy — the clone shares the original's micro-partitions via metadata pointers. New storage is consumed only when INSERT, UPDATE, or DELETE modifies data in either copy. Internal stages are NOT cloneable (error). External tables are excluded from database clones."},
  {"id":3,"domain":"D1: Architecture","multi":false,"text":"A table has 10,000 micro-partitions. A query filters on column REGION, which is not part of the clustering key. The Query Profile shows 9,800 partitions scanned. What is the most likely cause?","options":{"A":"The warehouse is undersized and cannot hold the partition metadata in SSD cache","B":"The result cache has been invalidated by a recent DML operation on the table","C":"The REGION column's values are distributed across most micro-partitions, causing overlapping min/max ranges","D":"Snowflake only prunes micro-partitions when the filter column is the clustering key"},"answer":["C"],"explanation":"Snowflake stores min/max statistics for ALL columns in each micro-partition, not just clustering key columns. However, if a column's values are spread randomly across partitions, the min/max ranges overlap extensively and almost no partitions can be eliminated. This is called poor natural clustering. Defining a clustering key on REGION would co-locate similar values and improve pruning."},
  {"id":4,"domain":"D1: Architecture","multi":false,"text":"An administrator runs SHOW VIEWS and can see the SQL definition of View_A but not View_B. Both views were created by the same role. What explains this difference?","options":{"A":"View_B has a row access policy that hides its definition","B":"View_B is a secure view, which hides the definition text from non-owner roles","C":"View_B was created with TRANSIENT keyword, which obscures the definition","D":"View_B references tables the administrator does not have SELECT on, so the definition is masked"},"answer":["B"],"explanation":"Secure views hide the view definition (SQL text) and internal query optimizations from all roles except the view owner. Standard views expose the definition to anyone with SHOW VIEWS access. Row access policies filter rows, not view definitions. TRANSIENT is not a view keyword."},
  {"id":5,"domain":"D1: Architecture","multi":false,"text":"A warehouse has AUTO_SUSPEND = 0 and AUTO_RESUME = TRUE. No queries have been submitted for 2 hours. What is the current state of the warehouse?","options":{"A":"Suspended, because no queries were submitted for over 60 seconds","B":"Running and consuming credits, because AUTO_SUSPEND = 0 means never auto-suspend","C":"Suspended, because AUTO_SUSPEND = 0 means immediate suspension after each query","D":"In a standby state that does not consume credits but maintains SSD cache"},"answer":["B"],"explanation":"AUTO_SUSPEND = 0 means the warehouse NEVER automatically suspends — it runs continuously and consumes credits even with no activity. To enable immediate suspension, set AUTO_SUSPEND = 1 (minimum 60 seconds). There is no standby state in Snowflake."},
  {"id":6,"domain":"D1: Architecture","multi":false,"text":"An analyst queries SNOWFLAKE.ACCOUNT_USAGE.QUERY_HISTORY for a query that completed 30 minutes ago. The query does not appear in the results. The analyst then checks INFORMATION_SCHEMA.QUERY_HISTORY and finds it immediately. What explains this?","options":{"A":"The analyst lacks the required privileges to read ACCOUNT_USAGE views","B":"ACCOUNT_USAGE views have a latency of up to 45 minutes, while INFORMATION_SCHEMA provides near-real-time results","C":"ACCOUNT_USAGE only records queries that ran longer than 60 seconds","D":"INFORMATION_SCHEMA retains queries for 365 days, providing a more complete history"},"answer":["B"],"explanation":"ACCOUNT_USAGE views have a latency of 45 minutes to 3 hours. INFORMATION_SCHEMA provides near-real-time data. However, INFORMATION_SCHEMA retains only 7-14 days of history (not 365 days — that is ACCOUNT_USAGE). ACCOUNT_USAGE records all queries regardless of duration."},
  {"id":7,"domain":"D1: Architecture","multi":false,"text":"A pipeline has three stages: Stage 1 joins orders with customers, Stage 2 aggregates by region, Stage 3 filters top regions and materializes output. Each stage must automatically refresh when upstream data changes. A colleague suggests using materialized views. Why is this approach problematic?","options":{"A":"Materialized views cannot be queried by downstream materialized views","B":"Materialized views do not support WHERE clauses","C":"Materialized views are limited to single base table queries and cannot perform joins","D":"Materialized views can only be refreshed manually using ALTER MATERIALIZED VIEW REFRESH"},"answer":["C"],"explanation":"Materialized views support only queries against a single base table — they cannot include joins, subqueries against other tables, or references to other MVs. Dynamic tables support complex queries including joins and can be chained into multi-stage pipelines with automatic refresh via TARGET_LAG."},
  {"id":8,"domain":"D1: Architecture","multi":false,"text":"Which of the following features is available in Snowflake Standard Edition?","options":{"A":"Multi-cluster warehouses with auto-scaling","B":"Dynamic data masking policies","C":"Materialized views","D":"Snowpipe continuous data loading"},"answer":["D"],"explanation":"Snowpipe is available in all Snowflake editions. Multi-cluster warehouses, dynamic data masking, and materialized views all require Enterprise Edition or higher."},
  {"id":9,"domain":"D1: Architecture","multi":false,"text":"Dynamic table DT_A has TARGET_LAG = DOWNSTREAM. Dynamic table DT_B references DT_A and has TARGET_LAG = '15 minutes'. No other dynamic tables reference DT_A. If DT_A's source data changes, when does DT_A refresh?","options":{"A":"DT_A refreshes every 15 minutes on a fixed schedule independent of DT_B","B":"DT_A refreshes only when explicitly triggered by EXECUTE IMMEDIATE for DT_A","C":"Snowflake schedules DT_A's refresh as needed so that DT_B can meet its 15-minute target lag","D":"DT_A never refreshes because DOWNSTREAM requires at least two downstream consumers"},"answer":["C"],"explanation":"TARGET_LAG = DOWNSTREAM delegates refresh scheduling to Snowflake. The system determines when to refresh DT_A based on the freshness requirements of its downstream consumers (in this case DT_B's 15-minute lag). DT_A does not have its own fixed schedule — Snowflake optimizes refresh timing to satisfy the pipeline."},
  {"id":10,"domain":"D1: Architecture","multi":false,"text":"A materialized view is defined on table ORDERS with a WHERE clause filtering status = 'SHIPPED'. A user queries SELECT * FROM ORDERS WHERE status = 'SHIPPED' AND region = 'US'. The user does not reference the materialized view. What happens?","options":{"A":"The query scans the full ORDERS table because the MV was not referenced in the FROM clause","B":"The query fails because materialized views require explicit references","C":"The optimizer may transparently rewrite the query to read from the MV if it determines this is more efficient","D":"The MV is used only if the query's WHERE clause exactly matches the MV's definition"},"answer":["C"],"explanation":"Snowflake's optimizer can automatically rewrite queries against the base table to read from a materialized view when the MV can satisfy the query. The WHERE clause does not need to match exactly — the optimizer checks if the MV's precomputed results can be used to answer the query. This is fully transparent to the user."},
  {"id":11,"domain":"D2: Security","multi":false,"text":"An account-level network policy allows the range 10.0.0.0/8. A user-level network policy on user JSMITH allows only 192.168.1.0/24. User JSMITH connects from IP 10.0.5.100. What happens?","options":{"A":"The connection succeeds because the IP is allowed by the account-level policy","B":"The connection is blocked because the user-level policy overrides the account policy, and the IP is not in 192.168.1.0/24","C":"Both policies are evaluated and the connection succeeds if either allows it","D":"The connection fails with a policy conflict error"},"answer":["B"],"explanation":"User-level network policies OVERRIDE account-level policies — they are not additive. When a user-level policy exists, ONLY that policy is evaluated. Since 10.0.5.100 is not in the user-level ALLOWED_IP_LIST of 192.168.1.0/24, the connection is blocked."},
  {"id":12,"domain":"D2: Security","multi":false,"text":"A developer creates a task without specifying a WAREHOUSE parameter. When attempting to resume the task, it fails with an insufficient privileges error. The role has CREATE TASK on the schema and EXECUTE TASK at the account level. What additional privilege is needed?","options":{"A":"OPERATE on the task","B":"EXECUTE MANAGED TASK at the account level","C":"USAGE on a warehouse","D":"MANAGE WAREHOUSES at the account level"},"answer":["B"],"explanation":"Tasks without a WAREHOUSE parameter use serverless compute. Running serverless tasks requires EXECUTE MANAGED TASK at the account level, in addition to EXECUTE TASK. OPERATE is needed for resuming/suspending tasks the role owns but is separate from the compute privilege issue here."},
  {"id":13,"domain":"D2: Security","multi":false,"text":"A security administrator wants to ensure that every table created in ANALYTICS.REPORTING going forward automatically grants SELECT to the ANALYST role, without affecting existing tables. Which statement achieves this?","options":{"A":"GRANT SELECT ON ALL TABLES IN SCHEMA ANALYTICS.REPORTING TO ROLE ANALYST","B":"GRANT SELECT ON FUTURE TABLES IN SCHEMA ANALYTICS.REPORTING TO ROLE ANALYST","C":"ALTER SCHEMA ANALYTICS.REPORTING SET DEFAULT_GRANTS = 'SELECT TO ANALYST'","D":"GRANT SELECT ON SCHEMA ANALYTICS.REPORTING TO ROLE ANALYST"},"answer":["B"],"explanation":"GRANT ... ON FUTURE TABLES applies only to tables created after the statement executes. ON ALL TABLES grants to existing tables. There is no DEFAULT_GRANTS schema property. GRANT ON SCHEMA grants schema-level usage, not table-level SELECT."},
  {"id":14,"domain":"D2: Security","multi":false,"text":"Table ownership is transferred from ROLE_A to ROLE_B using GRANT OWNERSHIP ON TABLE t1 TO ROLE ROLE_B REVOKE CURRENT GRANTS. The ANALYST role previously had SELECT on t1. After the transfer, ANALYST queries t1 and gets an insufficient privileges error. What happened?","options":{"A":"ROLE_B must explicitly grant USAGE on the table's schema to ANALYST","B":"The REVOKE CURRENT GRANTS clause removed all existing privileges on the object, including ANALYST's SELECT grant","C":"ANALYST must re-authenticate for the new ownership to take effect","D":"Table ownership transfers are not allowed between custom roles"},"answer":["B"],"explanation":"GRANT OWNERSHIP with REVOKE CURRENT GRANTS removes all existing outbound privileges on the object before transferring ownership. ANALYST's SELECT grant was revoked. To preserve existing grants during an ownership transfer, use COPY CURRENT GRANTS instead. If neither clause is specified and outbound grants exist, the command fails."},
  {"id":15,"domain":"D2: Security","multi":false,"text":"Which role can create new Snowflake accounts within an organization and enable replication between them?","options":{"A":"ACCOUNTADMIN in any account within the organization","B":"SECURITYADMIN with the MANAGE ACCOUNTS privilege","C":"ORGADMIN","D":"SYSADMIN with elevated organization privileges"},"answer":["C"],"explanation":"ORGADMIN is the organization-level role that can create accounts, enable replication between accounts, and view organization-level usage. ACCOUNTADMIN operates within a single account. SECURITYADMIN and SYSADMIN do not have cross-account capabilities."},
  {"id":16,"domain":"D2: Security","multi":false,"text":"A provider creates a reader account for a partner who does not have Snowflake. The partner runs several analytical queries using the reader account's warehouse. Who is billed for the compute?","options":{"A":"The partner, through a Snowflake pay-as-you-go arrangement","B":"The provider, since all reader account costs are charged to the provider's account","C":"Snowflake absorbs the cost as an incentive for data sharing adoption","D":"The compute is free because reader accounts use a shared system warehouse"},"answer":["B"],"explanation":"Reader accounts are created and fully managed by the provider. All compute and storage costs — including warehouse usage by the reader — are billed to the provider's Snowflake account. This is a critical cost consideration when offering reader accounts."},
  {"id":17,"domain":"D2: Security","multi":false,"text":"USERADMIN creates a new custom role DATA_LOADER and wants to grant it INSERT privileges on table ANALYTICS.RAW.EVENTS. Can USERADMIN perform this grant?","options":{"A":"Yes, USERADMIN can create roles and grant any privilege on any object","B":"No, USERADMIN can create roles and users but cannot grant object-level privileges like INSERT","C":"Yes, but only if USERADMIN also owns the ANALYTICS database","D":"No, only ACCOUNTADMIN can grant privileges on tables"},"answer":["B"],"explanation":"USERADMIN has CREATE USER and CREATE ROLE privileges and can assign roles to users/other roles. However, granting object-level privileges (SELECT, INSERT, etc.) requires SECURITYADMIN (via MANAGE GRANTS) or the object owner. USERADMIN does not inherit MANAGE GRANTS."},
  {"id":18,"domain":"D3: Loading","multi":false,"text":"Before loading 200 CSV files into a production table, an engineer wants to identify all rows across all files that would cause parsing errors, without inserting any data. Which approach is correct?","options":{"A":"Run COPY INTO with ON_ERROR = CONTINUE and check VALIDATE() afterward","B":"Run COPY INTO with VALIDATION_MODE = RETURN_ERRORS","C":"Run COPY INTO with FORCE = TRUE and TRUNCATECOLUMNS = TRUE","D":"Run COPY INTO with ON_ERROR = SKIP_FILE and review the error output"},"answer":["B"],"explanation":"VALIDATION_MODE = RETURN_ERRORS validates all files and returns all error rows WITHOUT loading any data. ON_ERROR = CONTINUE actually loads data (skipping bad rows). FORCE bypasses dedup but still loads data. SKIP_FILE skips entire files with errors during actual loading."},
  {"id":19,"domain":"D3: Loading","multi":false,"text":"An engineer loads Parquet files where the column names match the target table but in different order. The first load attempt fails with a type mismatch because columns were matched by ordinal position. Which COPY option fixes this?","options":{"A":"ERROR_ON_COLUMN_COUNT_MISMATCH = FALSE","B":"MATCH_BY_COLUMN_NAME = CASE_INSENSITIVE","C":"FORCE = TRUE","D":"STRIP_OUTER_ARRAY = TRUE"},"answer":["B"],"explanation":"MATCH_BY_COLUMN_NAME loads columns by matching names rather than ordinal position. CASE_INSENSITIVE handles case differences between file and table column names. ERROR_ON_COLUMN_COUNT_MISMATCH handles count mismatches, not ordering. STRIP_OUTER_ARRAY is for JSON. FORCE bypasses load metadata tracking."},
  {"id":20,"domain":"D3: Loading","multi":false,"text":"A VARIANT column stores JSON: {\"customer\": {\"addresses\": [{\"city\": \"NYC\"}, {\"city\": \"LA\"}]}}. An analyst needs each address as a separate row with the city value extracted. Which SQL pattern achieves this?","options":{"A":"SELECT PARSE_JSON(data:customer:addresses) FROM t","B":"SELECT f.value:city::STRING FROM t, LATERAL FLATTEN(INPUT => t.data:customer.addresses) f","C":"SELECT OBJECT_CONSTRUCT('city', data:customer:addresses) FROM t","D":"SELECT ARRAY_TO_STRING(data:customer:addresses, ',') FROM t"},"answer":["B"],"explanation":"LATERAL FLATTEN expands an array into separate rows. Each element becomes f.value, and f.value:city extracts the nested key. PARSE_JSON converts a string to VARIANT (the data is already VARIANT). OBJECT_CONSTRUCT builds new objects. ARRAY_TO_STRING concatenates array elements into a single string."},
  {"id":21,"domain":"D3: Loading","multi":false,"text":"A COPY INTO load with ON_ERROR = CONTINUE and PURGE = TRUE processes 50 files. 3 files have scattered bad rows. After the command completes, how many files remain on the stage?","options":{"A":"50 — PURGE is ignored when ON_ERROR = CONTINUE","B":"3 — only the files with errors remain","C":"0 — all 50 files are purged because CONTINUE processes every file","D":"47 — only completely clean files are purged"},"answer":["C"],"explanation":"With ON_ERROR = CONTINUE, Snowflake processes every file and loads all valid rows (skipping bad rows). PURGE = TRUE removes files that were processed — and since CONTINUE processes all files (including those with errors), all 50 files are purged. Files are only retained when SKIP_FILE causes them to be entirely skipped."},
  {"id":22,"domain":"D3: Loading","multi":false,"text":"A data team loads files into a table using bulk COPY INTO. They attempt to reload the same files 60 days later without using FORCE = TRUE. The COPY command completes but reports 0 rows loaded. Ten days after that (day 70), they try again without FORCE. What happens?","options":{"A":"0 rows loaded — Snowflake's load metadata never expires","B":"The files are loaded successfully because bulk COPY metadata is retained for 64 days and has now expired","C":"The files are loaded successfully because bulk COPY metadata is retained for 14 days","D":"The COPY command fails with a file-not-found error"},"answer":["B"],"explanation":"Bulk COPY INTO retains load metadata for 64 days. Within that window, Snowflake skips files already loaded (dedup). At day 60, metadata exists so files are skipped. At day 70, metadata has expired (>64 days), so files are treated as new and loaded again. Snowpipe retention is 14 days, not bulk COPY."},
  {"id":23,"domain":"D3: Loading","multi":false,"text":"A stream is created on table EVENTS. The table has DATA_RETENTION_TIME_IN_DAYS = 3 and MAX_DATA_EXTENSION_TIME_IN_DAYS = 14 (default). The stream goes unconsumed for 15 days. What is the stream's state?","options":{"A":"Active — the 14-day extension parameter keeps the stream valid","B":"Active — streams never go stale as long as the source table exists","C":"Stale — 15 days exceeds the greater of DATA_RETENTION (3) and MAX_DATA_EXTENSION (14)","D":"Stale — 15 days exceeds the DATA_RETENTION_TIME of 3 days"},"answer":["C"],"explanation":"Stream staleness is determined by the GREATER of DATA_RETENTION_TIME_IN_DAYS and MAX_DATA_EXTENSION_TIME_IN_DAYS. Here, max(3, 14) = 14 days. Since 15 > 14, the stream is stale and must be dropped and recreated. The retention value alone (3 days) would have made it stale much sooner, but the extension parameter gave it 14 days."},
  {"id":24,"domain":"D3: Loading","multi":false,"text":"A data engineer needs to download files from an internal named stage to a local machine for analysis. The engineer attempts the operation from a Snowsight worksheet. What is the result?","options":{"A":"The operation succeeds — Snowsight supports all stage operations","B":"The operation fails — GET requires SnowSQL or a Snowflake driver with local filesystem access","C":"The operation fails because GET only works with user stages, not named stages","D":"The operation succeeds but files are downloaded to a temporary Snowflake-managed location"},"answer":["B"],"explanation":"GET (and PUT) require a client with local filesystem access — SnowSQL CLI or Snowflake drivers (JDBC, Python connector, etc.). Snowsight runs in a browser and cannot access the local filesystem. GET works with all internal stage types (user, table, named)."},
  {"id":25,"domain":"D3: Loading","multi":false,"text":"Snowpipe loads files into a table continuously. The Snowpipe compute costs appear on the provider's bill. Which billing model describes how Snowpipe compute is charged?","options":{"A":"Per-second billing using the virtual warehouse specified in the pipe definition","B":"Per-second billing using Snowflake-managed serverless compute, with overhead charges for file management","C":"Flat hourly rate regardless of data volume","D":"No compute charge — Snowpipe only incurs storage costs for the stage"},"answer":["B"],"explanation":"Snowpipe uses Snowflake-managed serverless compute (not user warehouses). It is billed per-second based on actual compute time, plus a small overhead for file queue management. There is no user-specified warehouse in the pipe — compute is fully managed."},
  {"id":26,"domain":"D4: Performance","multi":false,"text":"A task is created with CREATE TASK my_task ... WAREHOUSE = my_wh AS ... A second task is created with CREATE TASK my_task2 ... AS ... (no WAREHOUSE specified). How do these tasks differ in their compute model?","options":{"A":"Both use the same warehouse — the second task inherits the session's current warehouse","B":"The first uses user-managed compute (specified warehouse); the second uses Snowflake-managed serverless compute","C":"The second task fails at creation time because WAREHOUSE is required","D":"The first uses dedicated compute; the second shares compute with other serverless tasks in the account"},"answer":["B"],"explanation":"Specifying WAREHOUSE makes the task user-managed (billed to that warehouse). Omitting WAREHOUSE makes it serverless (Snowflake provisions and manages compute). Serverless tasks require EXECUTE MANAGED TASK privilege. The task creation succeeds in both cases."},
  {"id":27,"domain":"D4: Performance","multi":false,"text":"A task DAG has root task T_ROOT with SCHEDULE = 'USING CRON 0 * * * * UTC'. T_ROOT has two children: T_A (AFTER T_ROOT) and T_B (AFTER T_ROOT). T_A has child T_C (AFTER T_A). The root task's WHEN condition evaluates to FALSE at the scheduled time. What executes?","options":{"A":"All tasks execute but return empty results","B":"Only T_ROOT runs; children are suspended until the next schedule","C":"No task in the DAG executes — the entire run is skipped","D":"T_A, T_B, and T_C run because child tasks ignore the root's WHEN condition"},"answer":["C"],"explanation":"When a root task's WHEN condition evaluates to FALSE, the entire DAG run is skipped — no compute is consumed by any task in the graph. The WHEN clause is evaluated before the task body executes. This is commonly used with SYSTEM$STREAM_HAS_DATA() to skip runs when no new data exists."},
  {"id":28,"domain":"D4: Performance","multi":false,"text":"A multi-cluster warehouse uses SCALING_POLICY = 'STANDARD' with MAX_CLUSTER_COUNT = 4. During a brief spike, 20 queries queue simultaneously. How does the STANDARD policy respond compared to ECONOMY?","options":{"A":"STANDARD and ECONOMY both wait 6 minutes before starting new clusters","B":"STANDARD starts additional clusters immediately as queries queue; ECONOMY waits to confirm sustained load before adding clusters","C":"STANDARD limits cluster additions to one per minute; ECONOMY adds all needed clusters instantly","D":"STANDARD scales up cluster size; ECONOMY scales out cluster count"},"answer":["B"],"explanation":"STANDARD scaling favors performance — it starts new clusters as soon as queries begin queuing. ECONOMY scaling conserves credits — it starts new clusters only when there is enough load to keep a cluster busy for at least 6 minutes. Both scale OUT (add clusters), not UP (resize)."},
  {"id":29,"domain":"D4: Performance","multi":false,"text":"A developer writes a UDF that needs to insert audit records into a logging table each time it is called. The UDF creation fails. Why?","options":{"A":"UDFs cannot be written in SQL","B":"UDFs cannot perform DML operations — they are limited to returning computed values without side effects","C":"UDFs require a warehouse to be specified at creation time","D":"UDFs cannot reference tables in other schemas"},"answer":["B"],"explanation":"UDFs (user-defined functions) return scalar or tabular values and cannot execute side effects like INSERT, UPDATE, DELETE, or DDL. For operations requiring DML, use a stored procedure instead. Both UDFs and stored procedures support SQL, JavaScript, Python, Java, and Scala."},
  {"id":30,"domain":"D4: Performance","multi":false,"text":"A developer needs to generate a sequence of 1,000 dates starting from '2025-01-01' without referencing any existing table. Which approach works in Snowflake?","options":{"A":"SELECT GENERATE_SERIES('2025-01-01'::DATE, '2027-09-27'::DATE, INTERVAL '1 DAY')","B":"SELECT DATEADD(DAY, SEQ4(), '2025-01-01'::DATE) FROM TABLE(GENERATOR(ROWCOUNT => 1000))","C":"SELECT RANGE(1, 1000) + '2025-01-01'::DATE","D":"SELECT NEXT VALUE FOR my_sequence FROM DUAL"},"answer":["B"],"explanation":"TABLE(GENERATOR(ROWCOUNT => n)) produces n rows without a base table. Combined with SEQ4() (auto-incrementing sequence function) and DATEADD, it generates date sequences. GENERATE_SERIES and RANGE are not Snowflake functions. DUAL is an Oracle concept not needed in Snowflake."},
  {"id":31,"domain":"D4: Performance","multi":false,"text":"A query aggregates employee names per department: SELECT dept, ARRAY_AGG(name) FROM emp GROUP BY dept. What is the data type of the second column in the result?","options":{"A":"VARCHAR — names are concatenated with commas","B":"VARIANT — Snowflake wraps aggregated values in VARIANT","C":"ARRAY — each group produces a Snowflake ARRAY of the aggregated values","D":"OBJECT — each group produces a key-value map"},"answer":["C"],"explanation":"ARRAY_AGG returns an ARRAY data type containing the aggregated values (e.g., ['Alice','Bob']). LISTAGG would return a delimited VARCHAR string. OBJECT_AGG returns an OBJECT (key-value pairs). The result is a native ARRAY, not VARIANT, though ARRAYs are stored in VARIANT internally."},
  {"id":32,"domain":"D4: Performance","multi":false,"text":"A data team sets ALTER SESSION SET QUERY_TAG = 'etl_pipeline_v2' at the start of their loading session. Where does this tag appear?","options":{"A":"As metadata attached to every table modified during the session","B":"In QUERY_HISTORY views, labeling all queries executed in that session for filtering and cost attribution","C":"As an object tag on the session's warehouse, visible via SHOW TAGS","D":"In the RESULT_SCAN output of each query"},"answer":["B"],"explanation":"QUERY_TAG is a session parameter that labels all queries in the session. The tag appears in QUERY_HISTORY (both INFORMATION_SCHEMA and ACCOUNT_USAGE) and is used for tracking, filtering, and cost attribution. It is not an object tag, does not attach to tables, and does not appear in RESULT_SCAN."},
  {"id":33,"domain":"D4: Performance","multi":false,"text":"A table stores JSON events in a VARIANT column named RAW. To extract the event type from {\"event\": {\"type\": \"click\"}}, which expression is correct?","options":{"A":"RAW.event.type::STRING","B":"JSON_EXTRACT(RAW, '$.event.type')","C":"RAW:event.type::STRING","D":"GET_PATH(RAW, 'event/type')::STRING"},"answer":["C"],"explanation":"Snowflake uses colon notation for VARIANT path traversal: column:key.subkey. RAW:event.type navigates to the nested 'type' key. The ::STRING cast converts the extracted VARIANT to a string. Dot notation without the leading colon (RAW.event.type) is invalid — the colon is required for the first key. JSON_EXTRACT is not a Snowflake function. GET_PATH uses dot separators, not slashes."},
  {"id":34,"domain":"D4: Performance","multi":false,"text":"SYSTEM$CLUSTERING_INFORMATION on a table shows average_overlap = 12.5 and average_depth = 8.2. The clustering key is on column ORDER_DATE. What does this indicate about query performance on ORDER_DATE filters?","options":{"A":"Excellent clustering — depth under 10 means most queries will be fully pruned","B":"Poor clustering — high overlap and depth mean many micro-partitions have overlapping ORDER_DATE ranges, reducing pruning effectiveness","C":"Normal state — all tables have depth between 5 and 15 by default","D":"The table is too small for clustering metrics to be meaningful"},"answer":["B"],"explanation":"Average overlap measures how many micro-partitions share overlapping value ranges for the clustering key. Average depth measures how many partitions a single value might span. Ideal values are close to 1. Values of 12.5 and 8.2 indicate significant degradation — reclustering (automatic or manual) may be needed."},
  {"id":35,"domain":"D4: Performance","multi":false,"text":"A task has ALLOW_OVERLAPPING_EXECUTION = FALSE (default). The task is scheduled every 5 minutes but the previous run is still executing when the next scheduled time arrives. What happens?","options":{"A":"The new run queues behind the active run and executes as soon as it finishes","B":"The new scheduled run is skipped entirely","C":"The active run is cancelled and the new run starts","D":"Both runs execute concurrently on separate compute resources"},"answer":["B"],"explanation":"With ALLOW_OVERLAPPING_EXECUTION = FALSE (the default), if the previous run is still active when the next scheduled time arrives, that run is skipped. It does not queue — it is simply omitted. Setting it to TRUE would allow concurrent execution."},
  {"id":36,"domain":"D5: Sharing","multi":false,"text":"A provider wants to share data with a consumer whose Snowflake account is in a different cloud region. The provider does not want to manually set up replication. Which sharing method supports this?","options":{"A":"A direct share, since Snowflake handles cross-region sharing automatically for all share types","B":"A listing with cross-region auto-fulfillment enabled","C":"An external table pointing to the provider's cloud storage bucket in the other region","D":"A reader account created in the consumer's region"},"answer":["B"],"explanation":"Listings (private or Marketplace) support cross-cloud auto-fulfillment — Snowflake handles replication transparently. Direct shares are limited to consumers in the same Snowflake region. External tables require the consumer to have their own storage access. Reader accounts exist in the provider's region."},
  {"id":37,"domain":"D5: Sharing","multi":false,"text":"A database is created with CREATE DATABASE staging_db TRANSIENT = TRUE. Within this database, a developer runs CREATE TABLE staging_db.public.events (id INT, payload VARIANT) without specifying TRANSIENT. What Fail-safe period does the EVENTS table have?","options":{"A":"7 days — the standard Fail-safe for permanent tables","B":"0 days — tables in a transient database inherit the transient property regardless of CREATE TABLE syntax","C":"1 day — transient tables have a reduced Fail-safe period","D":"7 days, because omitting TRANSIENT from CREATE TABLE creates a permanent table"},"answer":["B"],"explanation":"In a transient database, ALL objects inherit the transient property — even if CREATE TABLE does not specify TRANSIENT. Transient tables have 0 days of Fail-safe (and Time Travel limited to 0 or 1 day). The database-level transient setting cascades to all schemas and tables within it."},
  {"id":38,"domain":"D5: Sharing","multi":false,"text":"Table T1 has DATA_RETENTION_TIME_IN_DAYS = 10. A clone T2 is created from T1. The engineer then runs ALTER TABLE T2 SET DATA_RETENTION_TIME_IN_DAYS = 1. What is the Time Travel retention for T1 after this change?","options":{"A":"1 day — the ALTER on the clone also affects the source","B":"10 days — the source and clone have independent retention settings after cloning","C":"0 days — altering the clone's retention disables retention on the source","D":"5 days — Snowflake averages the retention between source and clone"},"answer":["B"],"explanation":"Clones inherit the source's retention setting at clone time, but they are independent objects afterward. Altering the clone's DATA_RETENTION_TIME_IN_DAYS does not affect the source table. T1 remains at 10 days. T2 is now 1 day."},
  {"id":39,"domain":"D5: Sharing","multi":true,"text":"Which TWO objects can be included in a Snowflake direct share? (Select TWO)","options":{"A":"Stored procedures","B":"Secure views","C":"Virtual warehouses","D":"Secure UDFs","E":"Tasks"},"answer":["B","D"],"explanation":"Direct shares can include tables, secure views, and secure UDFs. Stored procedures, virtual warehouses, tasks, stages, and non-secure views cannot be shared. Consumers use their own compute to query shared data."},
  {"id":40,"domain":"D5: Sharing","multi":false,"text":"A consumer creates a database from a direct share. The consumer attempts to run INSERT INTO shared_db.public.shared_table VALUES (1, 'test'). What is the result?","options":{"A":"The INSERT succeeds because the consumer has full access to shared objects","B":"The INSERT fails — shared databases are read-only; the consumer must CREATE TABLE AS SELECT to get a writable copy","C":"The INSERT succeeds but is not visible to the provider","D":"The INSERT fails because DML requires ACCOUNTADMIN role"},"answer":["B"],"explanation":"Shared data is strictly read-only for consumers. No INSERT, UPDATE, DELETE, MERGE, or CLONE operations are allowed on shared objects. To obtain a writable copy, the consumer must create a local table using CREATE TABLE ... AS SELECT from the shared object."},
];

const EXAMS = [
  { id:'e01', label:'Exam 01', subtitle:'BASELINE · Calibrated to real exam', questions: QUESTIONS_E01, badge:'S1-E01' },
  { id:'e02', label:'Exam 02', subtitle:'New Topics + Reinforcement', questions: QUESTIONS_E02, badge:'S1-E02' },
  { id:'e03', label:'Exam 03', subtitle:'100% Fresh Framings · No Repeats', questions: QUESTIONS_E03, badge:'S1-E03' },
  { id:'e04', label:'Exam 04', subtitle:'70%+ Fresh Angles · Debug/Edge Cases', questions: QUESTIONS_E04, badge:'S1-E04' },
  { id:'e05', label:'Exam 05', subtitle:'Credit Math · DTs · Transformations', questions: QUESTIONS_E05, badge:'S1-E05' },
  { id:'e06', label:'Exam 06', subtitle:'Streams · Cloning · DAGs · Semi-structured', questions: QUESTIONS_E06, badge:'S1-E06' },
];

// ─── Helpers ──────────────────────────────────────────────────────────────────

const fmt = (s) => {
  const m = Math.floor(s / 60).toString().padStart(2, '0');
  const sec = (s % 60).toString().padStart(2, '0');
  return `${m}:${sec}`;
};

const DomainTag = ({ domain }) => {
  const color = DOMAIN_COLORS[domain]?.bg ?? '#888';
  return (
    <span className="inline-block px-3 py-1 rounded-full text-white text-xs font-bold" style={{ background: color }}>
      {domain}
    </span>
  );
};

const domainCount = (questions, domain) => questions.filter(q => q.domain === domain).length;

// ─── CertificationExams ───────────────────────────────────────────────────────
const CertificationExams = () => {
  const [phase, setPhase] = useState('select'); // 'select' | 'landing' | 'running' | 'results'
  const [exam, setExam] = useState(null);
  const [order, setOrder] = useState([]);
  const [currentQ, setCurrentQ] = useState(0);
  const [answers, setAnswers] = useState({});
  const [flagged, setFlagged] = useState(new Set());
  const [timeLeft, setTimeLeft] = useState(EXAM_DURATION);
  const [shuffle, setShuffle] = useState(true);
  const [filterReview, setFilterReview] = useState('all');

  // ── Timer ──────────────────────────────────────────────────────────────────
  useEffect(() => {
    if (phase !== 'running') return;
    if (timeLeft <= 0) { setPhase('results'); return; }
    const id = setInterval(() => setTimeLeft(t => {
      if (t <= 1) { setPhase('results'); return 0; }
      return t - 1;
    }), 1000);
    return () => clearInterval(id);
  }, [phase, timeLeft]);

  // ── Exam start ────────────────────────────────────────────────────────────
  const startExam = () => {
    const n = exam.questions.length;
    const o = Array.from({ length: n }, (_, i) => i);
    if (shuffle) o.sort(() => Math.random() - 0.5);
    setOrder(o);
    setCurrentQ(0);
    setAnswers({});
    setFlagged(new Set());
    setTimeLeft(EXAM_DURATION);
    setPhase('running');
  };

  const submitExam = () => setPhase('results');

  const retake = () => { setPhase('landing'); };

  const backToSelect = () => { setExam(null); setPhase('select'); };

  // ── Score ─────────────────────────────────────────────────────────────────
  const calcScore = () => {
    if (!exam) return { correct: 0, total: 0, pct: 0, domainStats: {} };
    const total = exam.questions.length;
    let correct = 0;
    const domainStats = {};
    DOMAINS.forEach(d => { domainStats[d] = { correct: 0, total: 0 }; });
    order.forEach((qi, i) => {
      const q = exam.questions[qi];
      domainStats[q.domain].total++;
      const userAns = answers[i] ?? new Set();
      const isCorrect = JSON.stringify([...userAns].sort()) === JSON.stringify([...q.answer].sort());
      if (isCorrect) { correct++; domainStats[q.domain].correct++; }
    });
    return { correct, total, pct: (correct / total) * 100, domainStats };
  };

  // ── Answer handling ───────────────────────────────────────────────────────
  const toggleAnswer = (qIdx, key, isMulti) => {
    setAnswers(prev => {
      const cur = new Set(prev[qIdx] ?? []);
      if (isMulti) {
        if (cur.has(key)) cur.delete(key); else cur.add(key);
      } else {
        cur.clear(); cur.add(key);
      }
      return { ...prev, [qIdx]: cur };
    });
  };

  const toggleFlag = (idx) => {
    setFlagged(prev => {
      const s = new Set(prev);
      if (s.has(idx)) s.delete(idx); else s.add(idx);
      return s;
    });
  };

  // ─────────────────────────────────────────────────────────────────────────
  // RENDER: Exam Selector
  // ─────────────────────────────────────────────────────────────────────────
  if (phase === 'select') {
    return (
      <div className="space-y-6">
        <div className="bg-white rounded-2xl border border-purple-100 shadow-sm p-6">
          <div className="flex items-center gap-3 mb-2">
            <div className="bg-purple-600 p-2 rounded-xl">
              <BookOpen className="w-5 h-5 text-white" />
            </div>
            <div>
              <h2 className="text-lg font-bold text-slate-800">Season 1 · Mock Exams</h2>
              <p className="text-slate-500 text-xs">40 questions · 40-minute timer · Full review with explanations</p>
            </div>
          </div>
        </div>

        <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {EXAMS.map((ex, idx) => (
            <div
              key={ex.id}
              className="bg-white rounded-2xl border border-slate-200 shadow-sm hover:shadow-md transition-all cursor-pointer group"
              onClick={() => { setExam(ex); setPhase('landing'); }}
            >
              <div className="bg-purple-700 rounded-t-2xl p-4 flex items-center justify-between">
                <div>
                  <p className="text-purple-200 text-[10px] font-bold uppercase tracking-widest">COF-C03 · Season 1</p>
                  <h3 className="text-white font-extrabold text-base">{ex.label}</h3>
                </div>
                <span className="bg-white/20 text-white text-xs font-bold px-2.5 py-1 rounded-full">{ex.badge}</span>
              </div>
              <div className="p-4">
                <p className="text-slate-500 text-xs mb-3">{ex.subtitle}</p>
                <div className="space-y-1 mb-4">
                  {DOMAINS.map(d => (
                    <div key={d} className="flex items-center gap-2">
                      <div className="w-2 h-2 rounded-full flex-shrink-0" style={{ background: DOMAIN_COLORS[d]?.bg ?? '#888' }}></div>
                      <span className="text-xs text-slate-600">{d} — {domainCount(ex.questions, d)}q</span>
                    </div>
                  ))}
                </div>
                <div className="flex items-center justify-between">
                  <span className="text-xs text-slate-400">⏱ 40 min · 40 questions</span>
                  <div className="flex items-center gap-1 text-purple-600 font-bold text-xs group-hover:gap-2 transition-all">
                    Start <ChevronRight className="w-3.5 h-3.5" />
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  // ─────────────────────────────────────────────────────────────────────────
  // RENDER: Landing
  // ─────────────────────────────────────────────────────────────────────────
  if (phase === 'landing' && exam) {
    return (
      <div className="max-w-2xl mx-auto space-y-5">
        <div className="bg-purple-700 rounded-2xl p-6 text-white">
          <p className="text-purple-200 text-xs font-bold uppercase tracking-widest mb-1">COF-C03 · Season 1</p>
          <h2 className="text-2xl font-extrabold mb-1">{exam.label}</h2>
          <p className="text-purple-200 text-sm">{exam.subtitle}</p>
        </div>

        <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-5 grid sm:grid-cols-2 gap-4">
          <div>
            <p className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Domain Distribution</p>
            {DOMAINS.map(d => (
              <div key={d} className="flex items-center gap-2 mb-1.5">
                <div className="w-2.5 h-2.5 rounded-full flex-shrink-0" style={{ background: DOMAIN_COLORS[d]?.bg }}></div>
                <span className="text-sm text-slate-700">{d}</span>
                <span className="text-xs text-slate-400 ml-auto font-semibold">{domainCount(exam.questions, d)} questions</span>
              </div>
            ))}
          </div>
          <div>
            <p className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Exam Settings</p>
            <div className="space-y-2 text-sm text-slate-600">
              <div className="flex items-center gap-2">
                <Clock className="w-4 h-4 text-purple-500" />
                <span>40-minute countdown timer</span>
              </div>
              <div className="flex items-center gap-2">
                <CheckCircle className="w-4 h-4 text-emerald-500" />
                <span>Pass threshold: 75%</span>
              </div>
              <div className="flex items-center gap-2">
                <Flag className="w-4 h-4 text-amber-500" />
                <span>Flag questions for review</span>
              </div>
            </div>
            <div className="mt-4 flex items-center gap-2">
              <input
                type="checkbox"
                id="shuffle-chk"
                checked={shuffle}
                onChange={e => setShuffle(e.target.checked)}
                className="w-4 h-4 accent-purple-600"
              />
              <label htmlFor="shuffle-chk" className="text-sm text-slate-700 cursor-pointer">Shuffle question order</label>
            </div>
          </div>
        </div>

        <div className="flex gap-3">
          <button
            onClick={backToSelect}
            className="flex-1 bg-slate-100 hover:bg-slate-200 text-slate-700 font-semibold text-sm py-3 rounded-xl transition-colors flex items-center justify-center gap-2"
          >
            <ChevronLeft className="w-4 h-4" /> Back
          </button>
          <button
            onClick={startExam}
            className="flex-1 bg-purple-600 hover:bg-purple-700 text-white font-bold text-sm py-3 rounded-xl transition-colors flex items-center justify-center gap-2"
          >
            Start Exam <ChevronRight className="w-4 h-4" />
          </button>
        </div>
      </div>
    );
  }

  // ─────────────────────────────────────────────────────────────────────────
  // RENDER: Running Exam
  // ─────────────────────────────────────────────────────────────────────────
  if (phase === 'running' && exam) {
    const total = exam.questions.length;
    const qi = order[currentQ];
    const q = exam.questions[qi];
    const userAns = answers[currentQ] ?? new Set();
    const answeredCount = Object.keys(answers).length;
    const isFlagged = flagged.has(currentQ);

    const timerPct = (timeLeft / EXAM_DURATION) * 100;
    const timerColor = timeLeft > 600 ? 'bg-emerald-500' : timeLeft > 300 ? 'bg-amber-400' : 'bg-red-500';
    const timerText = timeLeft > 600 ? 'text-emerald-700' : timeLeft > 300 ? 'text-amber-700' : 'text-red-700';

    return (
      <div className="flex gap-4 items-start">
        {/* Sidebar */}
        <div className="w-52 flex-shrink-0 space-y-3 sticky top-4">
          {/* Timer */}
          <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-4">
            <div className="flex items-center gap-2 mb-2">
              <Clock className={`w-4 h-4 ${timerText}`} />
              <span className={`font-mono font-extrabold text-xl ${timerText}`}>{fmt(timeLeft)}</span>
            </div>
            <div className="w-full bg-slate-100 rounded-full h-2">
              <div className={`${timerColor} h-2 rounded-full transition-all`} style={{ width: `${timerPct}%` }}></div>
            </div>
            <p className="text-slate-400 text-[10px] mt-1">{answeredCount}/{total} answered</p>
          </div>

          {/* Progress */}
          <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-3">
            <p className="text-xs font-bold text-slate-500 mb-2">Progress</p>
            <div className="w-full bg-slate-100 rounded-full h-1.5 mb-1">
              <div className="bg-purple-500 h-1.5 rounded-full transition-all" style={{ width: `${(answeredCount / total) * 100}%` }}></div>
            </div>
            {flagged.size > 0 && <p className="text-[10px] text-amber-600 font-semibold">{flagged.size} flagged</p>}
          </div>

          {/* Navigator */}
          <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-3">
            <p className="text-xs font-bold text-slate-500 mb-2">Navigator</p>
            <div className="grid grid-cols-5 gap-1">
              {Array.from({ length: total }, (_, i) => {
                const isAnswered = answers[i] !== undefined && answers[i].size > 0;
                const isCur = i === currentQ;
                const isFlaggedQ = flagged.has(i);
                return (
                  <button
                    key={i}
                    onClick={() => setCurrentQ(i)}
                    className={`text-[10px] font-bold h-6 w-full rounded-md transition-colors ${
                      isCur ? 'bg-purple-600 text-white'
                      : isAnswered ? 'bg-emerald-100 text-emerald-800 hover:bg-emerald-200'
                      : 'bg-slate-100 text-slate-500 hover:bg-slate-200'
                    } ${isFlaggedQ ? 'ring-1 ring-amber-400' : ''}`}
                  >
                    {i + 1}
                  </button>
                );
              })}
            </div>
          </div>

          {/* Submit */}
          <button
            onClick={submitExam}
            className={`w-full py-2.5 rounded-xl text-sm font-bold transition-colors ${
              answeredCount === total
                ? 'bg-purple-600 hover:bg-purple-700 text-white'
                : 'bg-slate-200 text-slate-500 hover:bg-slate-300'
            }`}
          >
            Submit Exam
          </button>
          {answeredCount < total && (
            <p className="text-center text-xs text-slate-400">{total - answeredCount} unanswered</p>
          )}
        </div>

        {/* Main Question Area */}
        <div className="flex-1 bg-white rounded-2xl border border-slate-200 shadow-sm p-6">
          <div className="flex items-center justify-between mb-4">
            <DomainTag domain={q.domain} />
            <div className="flex items-center gap-2">
              <span className="text-sm text-slate-400 font-medium">Q {currentQ + 1} / {total}</span>
              <button
                onClick={() => toggleFlag(currentQ)}
                className={`flex items-center gap-1 text-xs font-semibold px-3 py-1.5 rounded-lg transition-colors ${
                  isFlagged ? 'bg-amber-100 text-amber-700' : 'bg-slate-100 text-slate-500 hover:bg-amber-50 hover:text-amber-600'
                }`}
              >
                <Flag className="w-3.5 h-3.5" />
                {isFlagged ? 'Flagged' : 'Flag'}
              </button>
            </div>
          </div>

          <p className="text-slate-800 font-semibold text-base leading-relaxed mb-5">{q.text}</p>

          {q.multi && (
            <p className="text-xs text-purple-600 font-bold mb-3 bg-purple-50 rounded-lg px-3 py-1.5 inline-block">
              Select all that apply (multi-select)
            </p>
          )}

          <div className="space-y-2.5 mb-6">
            {Object.entries(q.options).map(([key, val]) => {
              const isSelected = userAns.has(key);
              return (
                <button
                  key={key}
                  onClick={() => toggleAnswer(currentQ, key, q.multi)}
                  className={`w-full text-left flex items-start gap-3 p-3.5 rounded-xl border-2 transition-all text-sm ${
                    isSelected
                      ? 'border-purple-500 bg-purple-50 text-purple-900'
                      : 'border-slate-200 bg-white text-slate-700 hover:border-purple-300 hover:bg-purple-50/30'
                  }`}
                >
                  <div className={`w-6 h-6 rounded-full flex-shrink-0 flex items-center justify-center text-xs font-bold border-2 mt-0.5 ${
                    isSelected ? 'border-purple-500 bg-purple-500 text-white' : 'border-slate-300 text-slate-500'
                  }`}>
                    {key}
                  </div>
                  <span className="leading-relaxed">{val}</span>
                </button>
              );
            })}
          </div>

          <div className="flex items-center justify-between">
            <button
              onClick={() => setCurrentQ(q => Math.max(0, q - 1))}
              disabled={currentQ === 0}
              className="flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold bg-slate-100 text-slate-600 hover:bg-slate-200 disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
            >
              <ChevronLeft className="w-4 h-4" /> Previous
            </button>
            <button
              onClick={() => setCurrentQ(q => Math.min(total - 1, q + 1))}
              disabled={currentQ === total - 1}
              className="flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold bg-purple-600 text-white hover:bg-purple-700 disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
            >
              Next <ChevronRight className="w-4 h-4" />
            </button>
          </div>
        </div>
      </div>
    );
  }

  // ─────────────────────────────────────────────────────────────────────────
  // RENDER: Results
  // ─────────────────────────────────────────────────────────────────────────
  if (phase === 'results' && exam) {
    const { correct, total, pct, domainStats } = calcScore();
    const passed = pct >= 75;
    const emoji = pct >= 90 ? '🎉' : pct >= 75 ? '👍' : '📚';

    const reviewItems = order.map((qi, i) => {
      const q = exam.questions[qi];
      const userAns = answers[i] ?? new Set();
      const isCorrect = JSON.stringify([...userAns].sort()) === JSON.stringify([...q.answer].sort());
      const isFlaggedQ = flagged.has(i);
      return { q, i, userAns, isCorrect, isFlaggedQ };
    }).filter(({ isCorrect, isFlaggedQ }) => {
      if (filterReview === 'incorrect') return !isCorrect;
      if (filterReview === 'flagged') return isFlaggedQ;
      return true;
    });

    return (
      <div className="max-w-3xl mx-auto space-y-5">
        {/* Score header */}
        <div className={`rounded-2xl p-6 text-white ${passed ? 'bg-emerald-600' : 'bg-slate-700'}`}>
          <div className="flex items-center gap-3 mb-3">
            <span className="text-4xl">{emoji}</span>
            <div>
              <h2 className="text-2xl font-extrabold">{exam.label} — Results</h2>
              <p className="text-white/70 text-sm">{exam.subtitle}</p>
            </div>
          </div>
          <div className="grid grid-cols-3 gap-4">
            <div className="bg-white/20 rounded-xl p-3 text-center">
              <p className="text-white/70 text-xs">Score</p>
              <p className="text-2xl font-extrabold">{correct}/{total}</p>
            </div>
            <div className="bg-white/20 rounded-xl p-3 text-center">
              <p className="text-white/70 text-xs">Percentage</p>
              <p className="text-2xl font-extrabold">{pct.toFixed(1)}%</p>
            </div>
            <div className="bg-white/20 rounded-xl p-3 text-center">
              <p className="text-white/70 text-xs">Status</p>
              <p className="text-2xl font-extrabold">{passed ? 'PASS' : 'KEEP GOING'}</p>
              <p className="text-white/60 text-[10px]">{passed ? '≥75% target' : `${(pct - 75).toFixed(1)}% from 75%`}</p>
            </div>
          </div>
        </div>

        {/* Domain breakdown */}
        <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-5">
          <p className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-3">Domain Breakdown</p>
          <div className="space-y-2.5">
            {DOMAINS.map(d => {
              const s = domainStats[d];
              if (!s || s.total === 0) return null;
              const dPct = (s.correct / s.total) * 100;
              return (
                <div key={d} className="flex items-center gap-3">
                  <div className="w-32 flex-shrink-0">
                    <DomainTag domain={d} />
                  </div>
                  <div className="flex-1 bg-slate-100 rounded-full h-2.5">
                    <div
                      className="h-2.5 rounded-full transition-all"
                      style={{ width: `${dPct}%`, background: DOMAIN_COLORS[d]?.bg }}
                    ></div>
                  </div>
                  <span className="text-sm font-bold text-slate-700 w-20 text-right">
                    {s.correct}/{s.total} ({dPct.toFixed(0)}%)
                  </span>
                </div>
              );
            })}
          </div>
        </div>

        {/* Question review */}
        <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-5">
          <div className="flex items-center justify-between mb-4">
            <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Question Review</p>
            <div className="flex gap-1">
              {[['all','All'],['incorrect','Incorrect'],['flagged','Flagged']].map(([v, l]) => (
                <button
                  key={v}
                  onClick={() => setFilterReview(v)}
                  className={`text-xs font-semibold px-3 py-1.5 rounded-lg transition-colors ${
                    filterReview === v ? 'bg-purple-600 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
                  }`}
                >
                  {l}
                </button>
              ))}
            </div>
          </div>
          <div className="space-y-3">
            {reviewItems.map(({ q, i, userAns, isCorrect, isFlaggedQ }) => (
              <ReviewItem key={i} q={q} i={i} userAns={userAns} isCorrect={isCorrect} isFlaggedQ={isFlaggedQ} />
            ))}
          </div>
        </div>

        {/* Actions */}
        <div className="flex gap-3">
          <button
            onClick={backToSelect}
            className="flex-1 bg-slate-100 hover:bg-slate-200 text-slate-700 font-semibold text-sm py-3 rounded-xl transition-colors flex items-center justify-center gap-2"
          >
            <ChevronLeft className="w-4 h-4" /> All Exams
          </button>
          <button
            onClick={retake}
            className="flex-1 bg-purple-600 hover:bg-purple-700 text-white font-bold text-sm py-3 rounded-xl transition-colors flex items-center justify-center gap-2"
          >
            <RotateCcw className="w-4 h-4" /> Retake Exam
          </button>
        </div>
      </div>
    );
  }

  return null;
};

// ─── ReviewItem (collapsible) ────────────────────────────────────────────────
const ReviewItem = ({ q, i, userAns, isCorrect, isFlaggedQ }) => {
  const [open, setOpen] = useState(false);
  return (
    <div className={`rounded-xl border ${isCorrect ? 'border-emerald-200' : 'border-red-200'}`}>
      <button
        onClick={() => setOpen(o => !o)}
        className={`w-full flex items-center gap-3 p-3 text-left rounded-xl ${isCorrect ? 'bg-emerald-50' : 'bg-red-50'}`}
      >
        {isCorrect
          ? <CheckCircle className="w-4 h-4 text-emerald-500 flex-shrink-0" />
          : <XCircle className="w-4 h-4 text-red-400 flex-shrink-0" />}
        <span className="text-sm font-semibold text-slate-700 flex-1 text-left line-clamp-1">
          Q{i + 1}. {q.text}
        </span>
        {isFlaggedQ && <Flag className="w-3.5 h-3.5 text-amber-500 flex-shrink-0" />}
        <ChevronRight className={`w-4 h-4 text-slate-400 flex-shrink-0 transition-transform ${open ? 'rotate-90' : ''}`} />
      </button>
      {open && (
        <div className="p-4 pt-0 space-y-2">
          <p className="text-sm text-slate-700 font-medium mt-3 mb-2">{q.text}</p>
          <div className="space-y-1.5">
            {Object.entries(q.options).map(([key, val]) => {
              const isAnswer = q.answer.includes(key);
              const isUser = userAns.has(key);
              return (
                <div
                  key={key}
                  className={`text-sm px-3 py-2 rounded-lg flex items-start gap-2 ${
                    isAnswer && isUser ? 'bg-emerald-50 text-emerald-800 font-semibold'
                    : isAnswer ? 'bg-emerald-50 text-emerald-700 font-semibold'
                    : isUser ? 'bg-red-50 text-red-700 line-through'
                    : 'text-slate-600'
                  }`}
                >
                  <span className="font-bold w-4 flex-shrink-0">{key}.</span>
                  <span>{val}</span>
                  {isAnswer && isUser && <span className="ml-auto text-emerald-600 text-xs font-bold">✓ Correct</span>}
                  {isAnswer && !isUser && <span className="ml-auto text-emerald-600 text-xs font-bold">Correct answer</span>}
                  {!isAnswer && isUser && <span className="ml-auto text-red-500 text-xs font-bold">✗ Your answer</span>}
                </div>
              );
            })}
          </div>
          <div className="bg-slate-50 rounded-xl p-3 mt-2">
            <p className="text-xs font-bold text-slate-500 mb-1">Explanation</p>
            <p className="text-sm text-slate-700 leading-relaxed">{q.explanation}</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default CertificationExams;
